INSERT INTO `libros` (`id`, `titulo`, `subtitulo`, `descripcion`, `caracteristicas`, `video_archivo`, `video_url`, `created_at`, `updated_at`) VALUES
(21, 'MULTIPLEXADO - CIRCUITOS ELÉCTRICOS Y ELECTRÓNICOS I', NULL, 'Comunicación de intersistemas de las unidades de control en formato de curso. Descripción del funcionamiento teórico y práctico sobre los autos como: Peugeot, Ford, Renault, Fiat.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 29 cm.\",\"P\\u00e1ginas\":\"250\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 02:32:49', '2026-07-12 02:32:49'),
(22, 'MULTIPLEXADO - REDES CAN-BUS II', NULL, 'Localización de averías, fallas que representa la red can, formas de efectuar el diagnóstico: Motor, habitáculo y transmisión. Autos: Ford Focus, Ranger, Explorer, Peugeot 206, 406, Renault Clio, Meganne, Fiat Stylo,Punto Fire.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 29 cm\",\"P\\u00e1ginas\":\"308\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 02:34:39', '2026-07-12 02:34:39'),
(23, 'MULTIPLEXADO - REDES CAN-BUS III', NULL, 'Localización de averías, fallas que representa la red can, formas de efectuar el diagnóstico: Motor, habitáculo y transmisión. Autos como: Passat, Golf, Explorer, 307, 206, 406, Nissan.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 29 cm\",\"P\\u00e1ginas\":\"282\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 02:35:39', '2026-07-12 02:35:39'),
(24, 'MANUAL DE TREN DELANTERO I - Edición 2004', NULL, 'Aplicación para automóviles nacionales e importados.\r\nIntroducción básicos, terminología. Alfa Romeo 155, 156, Bmw E 36, Chrysler Neón, Voyager Caravan, Jeep Wrangler, Citroën Xsara, Fiat Ducato, Tempra, Ford Mondeo, Galaxy, Explorer, Peugeot 306, Renault Clio, Kangoo, Trafic, Seat Toledo, Ibiza, Córdoba, Swift, Toyota Hi-Lux, Hi-Ace, Volkswagen Polo Classic, Polo, Golf.\r\nDespiece y reparación. Ford Transit, Peugeot 406, Renault Kangoo, Volkswagen Passat.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"446\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 02:38:11', '2026-07-12 02:38:11'),
(25, 'MANUAL DE TREN DELANTERO II - Edición 2004', NULL, 'Aplicación para automóviles nacionales e importados.\r\nTablas de alineación. Alfa Romero 156, Sport, Chrysler Jeep Cherokee, Jeep Grand Cherokee, CitroenXantia, DaihatsuApplause, Sportrak, Fiat Ducato, Tipo, Ford Ka, Fiesta, Peugeot 205, 206, 306, Renault 9, 11, 19, Rover 200, Tourer 400, Mgf, SsangyongMusso, Suzuki Swift, Vitara, Toyota Corolla, Corolla 4x4, Volkswagen Transporter, Corrado.\r\nDespiece y reparación. Ford Focus, Peugeot 306, Renault Twingo, Volkswagen Polo Caddy.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"605\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 02:39:38', '2026-07-12 02:39:38'),
(26, 'MANUAL DE CLIMATIZACIÓN', NULL, 'Aire acondicionado y calefacción de automóviles y utilitarios nacionales e importados.\r\nGeneralidades, características, funcionalidad, aspectos problemáticos. Conductos, comandos, cable, reparto de aire, moto ventilador, radiador, condensador, evaporador, compresor. Calefacción. Chevrolet Meriva, Ford Escape, Ford Focus, Nissan Frontier, Renault Logan, Renault Trafic.', '{\"Tomos\":\"1\",\"Formato\":\"15 x 23 cm\",\"P\\u00e1ginas\":\"320\",\"Tapa\":\"R\\u00fastico\"}', NULL, NULL, '2026-07-12 03:04:28', '2026-07-12 03:04:28'),
(27, 'MANUAL DE TABLEROS Y AIRBAGS 1', NULL, 'Este manual será de utilidad para electricistas en general y tableristas, una herramienta útil para el trabajo de taller. Automóviles nacionales e importados.\r\nChevrolet Astra, Blazer S10, Meriva, Fiat Idea, Palio, Palio Weekend, Siena, Ford Fiesta, Nissan Frontier.', '{\"Tomos\":\"1\",\"Formato\":\"15 x 23 cm\",\"P\\u00e1ginas\":\"328\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:05:31', '2026-07-12 03:05:31'),
(28, 'MANUAL DE TABLEROS Y AIRBAGS 2', NULL, 'Este manual será de utilidad para electricistas en general y tableristas, una herramienta útil para el trabajo de taller. Automóviles nacionales e importados.\r\nPeugeot 106,  Peugeot 206, Peugeot 306, Peugeot 405, Peugeot 406, Renault Clio, Renault Laguna, Renault Master, Renault Trafic.', '{\"Tomos\":\"1\",\"Formato\":\"15 x 23 cm\",\"P\\u00e1ginas\":\"304\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:06:28', '2026-07-12 03:06:28'),
(29, 'MANUAL DE TERMINALES DEL MÓDULO DE CONTROL DEL MOTOR 1 - Edición 2006', NULL, 'Esta obra ofrece las señales eléctricas según los estados de funcionamiento del motor. Diagramas de pantallas de osciloscopio, símbolos utilizados y referencias generales.\r\nAlfa Romeo 145, 156, 164, Audi A4, Cabriolet, Bmw 318, 323, 525, Chevrolet Corsa, Astra, CitroënXsara, Xantia, Fiat Brava, Marea, Fiorino, Ford Escort, Transit, LandRoverRangeRover, Mazda 323, Mercedes Benz C Class, Mitsubishi Colt, Peugeot 106, Peugeot 306, Peugeot Boxer, Peugeot Partner, Renault Clio, 19, Master, Rover 400, Suzuki Vitara, Volkswagen Golf, Bora, Passat, Transporter, Vento, Volvo s40.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"304\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:07:28', '2026-07-12 03:07:28'),
(30, 'MANUAL DIAGNÓSTICO Y BÚSQUEDA DE FALLAS 6 - Edición 2011', NULL, 'Este manual está diseñado para facilitar el uso de los lectores de módulo de control para saber los valores normales, forma de lectura e interpretación de los estados eléctricos y encontrar todas las fallas en el sistema de inyección. Automóviles nacionales e importados.\r\nAudi A3, Bmw 1 series (E81/82/87), Chevrolet Astra, Corsa, Citroën C1, C2, C4, Fiat Punto, Tipo.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"568\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:08:39', '2026-07-12 03:08:39'),
(31, 'MANUAL DE BUJÍAS', NULL, 'Un completo manual que trae desde el origen de la bujía de encendido, el sistema de encendido hasta el proceso y el rendimiento. Motores Nafteros y Diesel. Incluye Tablas de aplicación.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"172\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:10:21', '2026-07-12 03:10:21'),
(32, 'MANUAL SOBREALIMENTACIÓN DE MOTORES DIESEL Y NAFTEROS - TURBOCOMPRESORES', NULL, 'La obra destinada a estudiantes  y mecánicos que se interesan en la sobrealimentación de motores y deseen conocer el funcionamiento y las prestaciones de un turbo. Funcionamiento, estructura, reemplazo, circuitos de aceite y agua.', '{\"Tomos\":\"1\",\"Formato\":\"15 x 22 cm\",\"P\\u00e1ginas\":\"216\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:11:32', '2026-07-12 03:11:32'),
(33, 'MANUAL GNC 1', NULL, 'Este manual ampliamente ilustrado describe la reparación y el mantenimiento de los sistemas de GNC, incluyendo el despiece del “corazón” de la instalación.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 22 cm\",\"P\\u00e1ginas\":\"288\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:12:38', '2026-07-12 03:12:38'),
(34, 'MANUAL GNC 2', NULL, 'En este segundo tomo se pone énfasis en una completa y minuciosa descripción de la electrónica ligada a los equipos de GNC de tercera y cuarta generación, los cuales son de masiva aplicación en la actualidad en todo tipo de automóviles y vehículos comerciales.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"402\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:13:44', '2026-07-12 03:13:44'),
(35, 'MANUAL CONTROL ELECTRONICO DEL MOTOR DIESEL - CAMIONES Y OMNIBUS', NULL, 'El manual describe a los sistemas más utilizados en la actualidad por los principales productores de motores y vehículos, así como a las tareas de diagnosis, detección de fallas y reparaciones, utilizando equipo de comprobación especial.\r\nSistema bomba inyector, tubería inyector bomba, aplicación Mercedes Benz, Scania, Volvo, Iveco.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"222\",\"Tapa\":\"R\\u00fastico\"}', NULL, NULL, '2026-07-12 03:14:53', '2026-07-12 03:14:53'),
(36, 'MANUAL DE UBICACIÓN DE COMPONENTES, RELÉS, CABLEADOS Y FUSIBLES 2 - Edición 2006', NULL, 'Este manual cuenta con novecientas ilustraciones que resulta una obra de consulta constante más aún si tomamos en cuenta el grado de tecnología utilizado en los automóviles de última generación, los cuales suman una gran cantidad de circuitos centrales y periféricos que los convierten en complicados mecanismos al servicio de seguridad y confort.\r\nAlfa Romeo 156, Chrysler Grand Cherokee, Neon, Fiat Ducato, Siena, Ford Transit, Peugeot Partner, Renault Clio, Renault Laguna.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"816\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:15:51', '2026-07-12 03:15:51'),
(37, 'MANUAL DE UBICACIÓN DE COMPONENTES, RELÉS, CABLEADOS Y FUSIBLES 5 – Edición 2011', NULL, 'Este manual cuenta con novecientas ilustraciones que resulta una obra de consulta constante más aún si tomamos en cuenta el grado de tecnología utilizado en los automóviles de última generación, los cuales suman una gran cantidad de circuitos centrales y periféricos que los convierten en complicados mecanismos al servicio de seguridad y confort.\r\nChevrolet Celta, Fiat Punto, Ford Ka, Peugeot 307, Renault Megane Scenic, Volkswagen Fox.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"432\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 03:16:42', '2026-07-12 03:16:42'),
(38, 'PROCEDIMIENTOS TÉCNICOS EN URGENCIAS - Medicina Crítica y Pacientes de Riesgo', NULL, 'HARCOURT / ERGON\r\n\r\nRealizada por un equipo de 125 expertos de todas las especialidades médicas, esta obra recoge las principales técnicas y procedimientos para el cuidado de pacientes críticos, con la descripción paso a paso de los procesos médicos fundamentales. Estructurada en 70 capítulos, agrupados en función de los órganos y sistemas del cuerpo humano. Gran cantidad de elementos gráficos: fotografías, imágenes diagnósticas, ilustraciones, esquemas, tablas, gráficos, etc. Pruebas de laboratorio, protocolos de actuación, tablas comparativas de fármacos y aspectos prácticos de la atención al paciente. Amplias secciones de bibliografía complementaria.', '{\"Tomos\":\"1\",\"Formato\":\"18 x 25 cm\",\"P\\u00e1ginas\":\"992\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura con sobrecubiertas\"}', NULL, NULL, '2026-07-12 03:32:44', '2026-07-12 03:32:44'),
(39, 'TRATADO DE MEDICINA DE URGENCIAS - Medicina Crítica y Pacientes de Riesgo', NULL, 'HARCOURT / ERGON\r\n\r\nPor primera vez, una obra reúne todo el cuerpo teórico de la medicina de urgencias junto con la práctica asistencial, tanto para el aprendizaje de la especialidad como para el ejercicio diario en el servicio de urgencias hospitalario. Todos los elementos para tomar las decisiones óptimas en un ámbito en que el tiempo es primordial para la curación del paciente.', '{\"Tomos\":\"2\",\"Formato\":\"23 x 20 cm\",\"P\\u00e1ginas\":\"1800\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura con sobrecubiertas\"}', NULL, NULL, '2026-07-12 03:34:33', '2026-07-12 03:34:33'),
(40, 'NUEVO TRATADO DE PEDIATRÍA - Medicina Crítica y Pacientes de Riesgo', NULL, 'HARCOURT / ERGON\r\n\r\nTodos los temas médicos relacionados con la pediatría, desde un triple enfoque: asistencial, docente e investigador. Actualizado con todas las novedades y avances diagnósticos y terapéuticos, desde la neonatología hasta la adolescencia. Gran cantidad de recursos gráficos: fotografías, radiografías, imágenes diagnósticas, ilustraciones, esquemas, cuadros, tablas, gráficos y láminas a todo color. Extensos apéndices con procedimientos diagnósticos y terapéuticos.', '{\"Tomos\":\"2\",\"Formato\":\"23 x 30 cm\",\"P\\u00e1ginas\":\"2616\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura con sobrecubiertas\"}', NULL, NULL, '2026-07-12 03:35:58', '2026-07-12 03:35:58'),
(41, 'MANUAL COMPLETO DE ENFERMERÍA - FUNDAMENTOS Y BASES DE TODAS LAS BASES ENFERMERAS', NULL, 'Esta obra es un tratado de todo el conocimiento de enfermería, orientada a la comprobación constante del saber. Está completamente ilustrada con fotografías y gráficos de apoyo, además de incluir resúmenes y evaluaciones.', '{\"Etiqueta\":\"Agotado\",\"Tomos\":\"2\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"1206\",\"Estuche\":\"Caja r\\u00edgida\"}', NULL, NULL, '2026-07-12 03:37:58', '2026-07-12 03:37:58'),
(42, 'FUNDAMENTOS PRÁCTICOS DE ENFERMERÍA - Pruebas Diagnósticas', NULL, 'Un instrumento práctico y eficaz de la mayoría de las pruebas de laboratorio, radiología e imagen y medicina nuclear, entre otras. Esta obra ilustrada incluye más de 400 descripciones de pruebas diagnósticas y su correspondiente paso a paso. En cada prueba se presenta el concepto, el sistema afectado y los valores de referencia; indicaciones, patologías; descripción de la actividad específica pre, durante y post; posibles contraindicaciones y complicaciones y la bibliografía de referencia.', '{\"Tomos\":\"2\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"712\",\"Estuche\":\"Caja r\\u00edgida\"}', NULL, NULL, '2026-07-12 03:39:15', '2026-07-12 03:39:15'),
(43, 'MANUAL DE ENFERMERÍA - TRAUMATOLOGÍA Y ORTOPEDIA', NULL, 'Comprende los principios generales de la enfermería traumatológica, las alteraciones más importantes del sistema músculo esquelético y los avances en cirugía ortopédica. Tiene capítulos especiales de implantes ortopédicos, fisiología, cirugía ortopédica y vendajes.', '{\"Tomos\":\"1\",\"Formato\":\"21 x 26 cm\",\"P\\u00e1ginas\":\"510\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:40:27', '2026-07-12 03:40:27'),
(44, 'MANUAL DE ENFERMERÍA - TÉCNICAS Y PROCEDIMIENTOS', NULL, 'Un instrumento práctico eficaz y de alto valor en la consulta rápida. Abarca la totalidad de las áreas de trabajo de enfermeras. Completamente ilustrado con fotografías y dibujos. Incluye índice alfabético general, analítico y por sistemas.', '{\"Tomos\":\"1\",\"Formato\":\"21 x 26 cm\",\"P\\u00e1ginas\":\"761\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:41:36', '2026-07-12 03:41:36'),
(45, 'URGENCIAS EN ENFERMERÍA', NULL, 'Un completo tratado para el aprendizaje y la resolución de problemas en urgencias. Se trata de una herramienta completa y útil para profesionales y estudiantes de enfermería.', '{\"Tomos\":\"1\",\"Formato\":\"21 x 27 cm\",\"P\\u00e1ginas\":\"570\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:42:33', '2026-07-12 03:42:33'),
(46, 'MANUAL DE ENFERMERÍA - PRIMEROS AUXILIOS  Guía para enfermeros y paramédicos', NULL, 'Esta obra sitúa al profesional de enfermería ante la posibilidadde tratar una víctima en la calle sin más medios que sus propiasmanos, o de tratarla en cualquier centro sanitario. Tiene materialespecializado tanto para el diagnóstico como para eltratamiento. Incluye un capítulo especial para actuar en accidentesde automóviles y de motocicletas.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"300\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 03:43:35', '2026-07-12 03:43:35'),
(47, 'ENFERMERÍA EN PSIQUIATRÍA Y SALUD MENTAL', NULL, 'El texto aborda el tema de la atención médica en situaciones de salud mental de forma amplia, desde su inicio, en la presentación de las bases conceptuales de la psicopatología y la psiquiatría y la evolución de la sociedad actual, para luego entrar en los cuadros de alteración de la salud mental, incluidas las urgencias psiquiátricas y los tratamientos farmacológicos más utilizados.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"631\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:44:41', '2026-07-12 03:44:41'),
(48, 'MANUAL COMPLETO DE NUTRICIÓN Y DIETÉTICA', NULL, 'Se trata de un texto enfocado sobre todo en el conocimiento teórico su aplicación práctica, fundamentalmente desde una imagen de la enfermera como promotora de la salud de la población y educadora en el importante campo de la vida cotidiana que es la alimentación.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"655\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:45:54', '2026-07-12 03:45:54'),
(49, 'ENFERMERÍA PEDIÁTRICA', NULL, 'Facilita una rápida consulta para situaciones múltiples en la atención infantil.', '{\"Tomos\":\"1\",\"Formato\":\"27 x 24 cm\",\"P\\u00e1ginas\":\"244\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:46:53', '2026-07-12 03:46:53'),
(50, 'ENFERMERÍA OBSTÉTRICA', NULL, 'Esta obra facilita, de forma didáctica, el acceso al conocimiento de las cuestiones propias de la especialidad y del manejo de procesos concretos debidamente actualizados.', '{\"Tomos\":\"1\",\"Formato\":\"17 x 24 cm\",\"P\\u00e1ginas\":\"244\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:47:55', '2026-07-12 03:47:55'),
(51, 'ENFERMERÍA EN TERAPIA INTENSIVA', NULL, 'Obra guía de intervención rápida, presenta actividades organizadas de forma práctica para abordar el cuidado en los cuadros fisiopatológicos que precisan cuidados intensivos.', '{\"Tomos\":\"1\",\"Formato\":\"17 x 24 cm\",\"P\\u00e1ginas\":\"244\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:48:47', '2026-07-12 03:48:47'),
(52, 'DICCIONARIO MÉDICO ILUSTRADO COLOR', NULL, 'Incluye más de 50.000 términos y sus distintas acepciones, definidos y acompañados por ilustraciones y fotografías a todo color.\r\n\r\n·INCLUYE LÁMINAS DE LA ANATOMÍA Y FISIOLOGÍA\r\n·TÉRMINOS MÉDICOS\r\n·VARIAS ACEPCIONES\r\n·MÁS DE 10.000 IMÁGENES A TODO COLOR', '{\"Tomos\":\"1\",\"Formato\":\"20 x 27 cm\",\"P\\u00e1ginas\":\"1050\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 03:50:09', '2026-07-12 03:50:09'),
(53, 'TEXAS HOLD´EM NL- NO LIMIT POKER', NULL, 'Todos los trucos y las técnicas para convertirse en un jugador de póker. Esta colección está dirigida a quienes no conocen el TEXAS HOLD\'EM NO LIMIT POKER, a los que lo practican intuitivamente y a aquellos que ya tienen nociones básicas y desean profundizarlas. Se trata de un curso didáctico y completo.', '{\"Tomos\":\"1\",\"Formato\":\"19 x 26 cm\",\"P\\u00e1ginas\":\"385\",\"Estuche\":\"Caja r\\u00edgida\"}', NULL, NULL, '2026-07-12 06:58:31', '2026-07-12 06:58:31'),
(54, 'SUPER SYSTEM DELUXE - EXPERTOS', NULL, 'Consejos de los expertos y mejores jugadores de póker del mundo. Liderado por el legendario DoyleBrunson, dos veces campeón del evento principal de la World Series of Poker (WSOP) y ganador de 10 brazaletes de oro. SuperSystemDeluxe reúne a varios de los mejores jugadores de todos los tiempos que revelan sus secretos para ganar.', '{\"Tomos\":\"3\",\"Formato\":\"19 x 26 cm\",\"P\\u00e1ginas\":\"760\",\"Estuche\":\"Caja r\\u00edgida\"}', NULL, NULL, '2026-07-12 06:59:47', '2026-07-12 06:59:47'),
(55, 'EL PAPA FRANCISCO - PENSAMIENTO Y PALABRAS PARA EL ALMA', NULL, 'Un libro imprescindible acerca del hombre que está revolucionando la Iglesia y el papel del papado, una colección de las frases más hermosas del pontífice que nos pide que nos concentremos “en lo esencial, en lo necesario, que es también lo que más apasiona y atrae”.', '{\"Tomos\":\"1\",\"Formato\":\"18 x 21 cm\",\"P\\u00e1ginas\":\"207\",\"Tapa\":\"Dura con sobre cubierta\"}', NULL, NULL, '2026-07-12 07:01:35', '2026-07-12 07:01:35'),
(56, 'CELIA - LA REPOSTERÍA Y SU ARTE', NULL, 'En delicada presentación para abordar con éxito el aprendizaje y perfeccionamiento en la decoración clásica de tortas. Incluye moldería.', '{\"Tomos\":\"1\",\"Formato\":\"21 x 29 cm\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 07:02:57', '2026-07-12 07:02:57'),
(57, 'PORCELANA FRÍA Y ALGO MÁS...', NULL, 'Obra con simple explicación para realizar bellos souvenirs, adornos, maceteros, portarretratos y muchas cosas más con distintas dificultades, detallando el tiempo aproximado de elaboración y costo de la realización. Incluye moldes en tamaño real.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"144\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-12 07:04:14', '2026-07-12 07:04:14'),
(58, 'DULCE COMPAÑIA', NULL, 'Una obra para dejar registrado los momentos más emotivos de la niñez, señalando el camino de Dios. Bautismo, canciones de cuna, oraciones, villancicos y muchas ideas para organizar la fiesta de bautismo y comunión.', '{\"Tomos\":\"1\",\"Formato\":\"23 x 33 cm\",\"P\\u00e1ginas\":\"136\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 07:06:17', '2026-07-12 07:06:17'),
(59, 'MI BEBÉ - El diario del primer capítulo de tu vida.', NULL, 'Un hermoso libro donde se podrán atesorar los hermosos momentos de su vida. Dejando escrito desde sus primeros pasos por la vida. En un maravilloso tomo lujosamente impreso a todo color con encuadernación de acolchada. Incluye un CD de audio donde encontraras todos los cuentos del libro narrados.', '{\"Tomos\":\"1\",\"Formato\":\"23 x 33 cm\",\"P\\u00e1ginas\":\"128\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 07:08:04', '2026-07-12 07:08:04'),
(60, 'EL ÁLBUM DE MI BEBÉ - Graba y reproduce la voz del bebé', NULL, 'Crea un libro de recuerdos y mensajes para que tus hijos atesoren durante toda su vida. Pega fotos y escribe anotaciones sobre los momentos más importantes de los primeros doce meses de tu bebé.\r\n\r\n¡ADEMÁS PODES GRABAR SU VOZ Y REPRODUCIRLA!', '{\"Tomos\":\"1\",\"Formato\":\"30 x 23 cm\",\"P\\u00e1ginas\":\"24 de cart\\u00f3n a todo color\",\"Estuche\":\"Caja\"}', NULL, 'https://youtu.be/YJLcIneMo78', '2026-07-12 07:11:02', '2026-07-12 07:11:02'),
(61, 'A FUEGO LENTO - COCINA CRIOLLA', NULL, 'Una propuesta para cocinar comidas criollas con elementos naturales y tradicionales. Encontrarán desde cómo construir una parrilla, asar en la cruz, y más de 200 recetas saladas y dulces. Incluye 3 minilibros con aderezos, conservas dulces y conservas saladas.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"234\",\"Estuche\":\"Caja\",\"Incluye\":\"3 Mini libros de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 07:14:27', '2026-07-12 07:14:27'),
(62, 'A FUEGO LENTO – COCINA LIGHT Y VIDA SANA (Serie Saludable)', NULL, 'En esta colección encontrará información detallada para lograr una alimentación equilibrada y variada, teniendo en cuenta las diferentes edades y actividades. Asií como también, que cocinar a personas con distintas patologías. Incluye tres mini libros con recetas de ensaladas, aguas e infusiones y juegos y licuados. Una propuesta para cuidar su salud, comiendo rico y sano.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"256\",\"Estuche\":\"Caja\",\"Incluye\":\"3 Mini libros de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 07:15:51', '2026-07-12 07:15:51'),
(63, 'TORTAS & CANDY PARTY', NULL, 'Básicos de PASTELERÍA\r\nDecoración de MESAS TEMÁTICAS\r\nTORTAS TEMÁTICAS\r\n \r\n\r\nCremas para decorar y rellenar, Pastas para cubrir tortas, Técnicas, Cupcakes, Cookies, Popcakes, Moldes y ¡MUCHOS SECRETOS POR DESCUBRIR!', '{\"Tomos\":\"1\",\"Formato\":\"19 x 26 cm\",\"P\\u00e1ginas\":\"476\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 07:17:52', '2026-07-12 07:17:52'),
(64, 'LOS CUADERNOS DE LA NONNA  COCINA ITALIANA - Colección N°2', NULL, 'PESCADOS Y MARISCOS - VEGETALES Y LEGUMBRES - TARTAS DULCES Y SALADAS\r\n\r\n \r\n\r\nEs una recopilación de las mejores recetas caseras de la auténtica cocina italiana, para saborear y rememorar los platos inolvidables que preparan las abuelas. Hemos realizado un viaje al pasado, de la mano de los recuerdos más preciados: aromas y sabores entrañables, una caricia para el corazón.\r\n\r\n\r\nEn esta colección podrás encontrar deliciosas tartas y pasteles dulces, riquísimas opciones con vegetales y una selección de platos típicos con pescados y mariscos de todo tipo.', '{\"Tomos\":\"3\",\"Formato\":\"20 x 27 cm\",\"P\\u00e1ginas\":\"336\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 07:20:52', '2026-07-12 07:20:52'),
(65, 'LOS CUADERNOS DE LA NONNA  COCINA ITALIANA - Colección N°1', NULL, 'ARROCES Y RISOTTOS - PASTAS CASERAS - POSTRES TÍPICOS\r\n\r\nEs una recopilación de las mejores recetas caseras de la auténtica cocina italiana, para saborear y rememorar los platos inolvidables que preparan las abuelas. Hemos realizado un viaje al pasado, de la mano de los recuerdos más preciados: aromas y sabores entrañables, una caricia para el corazón.\r\n\r\nEn esta colección podrás encontrar deliciosas recetas de arroz con carnes y vegetales, recetas de pasta fresca básica y diferentes técnicas de elaboración y por último una selección de postres tradicionales.', '{\"Tomos\":\"3\",\"Formato\":\"20 x 27 cm\",\"P\\u00e1ginas\":\"336\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 07:23:01', '2026-07-12 07:23:01'),
(66, 'REPOSTERÍA UN ARTE FAMILIAR', NULL, 'Más de 240 recetas desarrolladas en forma clara y amena para que cocinar sea realmente un deleite para compartir en familia; incluye recetas de chocolate, exquisiteces de panadería, dulces para CELÍACOS y DIABÉTICOS, hasta los más variados postres. Con sugerencias y consejos prácticos para aprovechar al máximo los valores nutrientes y las técnicas de repostería.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 29 cm\",\"P\\u00e1ginas\":\"320\",\"Estuche\":\"Caja\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-12 07:24:16', '2026-07-12 07:26:10'),
(67, 'COCINAR - UN ARTE FAMILIAR', NULL, 'Más de 545 recetas desarrolladas en forma clara y amena para que cocinar sea realmente un deleite para compartir en familia; incluye recetas dulces y para celíacos y diabéticos. Con sugerencias y consejos prácticos para aprovechar al máximo los valores nutrientes y las técnicas de cocina.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 29 cm\",\"P\\u00e1ginas\":\"320\",\"Estuche\":\"Caja\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-12 07:25:45', '2026-07-12 07:25:45'),
(68, 'ENCICLOPEDIA DIDÁCTICA UNIVERSAL', NULL, 'Una colección imprescindible que cuenta con todas las materias sobre las ciencias sociales.\r\nLiteratura, psicología, antropología, filosofía, religiones y ética, sociología y política, economía, derecho, geografía, atlas y banderas, historia del arte, música, historia universal, historia de América Latina, cronología. Incluye un tomo de cómo estudiar con éxito.', '{\"Tomos\":\"5\",\"Formato\":\"20 x 26 cm\",\"P\\u00e1ginas\":\"1204\",\"Estuche\":\"Caja\"}', NULL, NULL, '2026-07-12 07:37:32', '2026-07-12 07:37:32'),
(69, 'ENCICLOPEDIA TEMÁTICA UNIVERSAL', NULL, 'Una colección imprescindible que cuenta con todas las materias de forma completa y útil.\r\nMatemáticas, geometría, estadística, computación, astronomía, astronáutica, física, electricidad y electrónica, química, el cuerpo humano, paleontología, biología, botánica, zoología, geología, educación cívica, ecología, atlas, geografía, gramática, educación artística. Incluye un tomo con técnicas de estudio.', '{\"Tomos\":\"5\",\"Formato\":\"20 x 26 cm\",\"P\\u00e1ginas\":\"1452\",\"Estuche\":\"Caja\"}', NULL, NULL, '2026-07-12 07:38:42', '2026-07-12 07:38:42'),
(70, 'ENCICLOPEDIA UNIVERSAL DE CIENCIAS SOCIALES', NULL, 'Una obra completa con todas las áreas de las Ciencias Sociales. Literatura, Filosofía, Psicología, Derecho, Economía, Sociología, Política, Antropología, Arte, Geografía, Historia.', '{\"Tomos\":\"1\",\"Formato\":\"19 x 26 cm\",\"P\\u00e1ginas\":\"1072\",\"Estuche\":\"Caja\"}', NULL, NULL, '2026-07-12 07:40:03', '2026-07-12 07:40:03'),
(71, 'LEER Y VER UNIVERSO Y SISTEMA SOLAR', NULL, 'Una obra que les permitirá recorrer los conceptos principales sobre el Cosmos, los planetas y los satélites que nos rodean teniendo en cuenta, además, las más recientes teorías sobre estructuras y evolución.', '{\"Tomos\":\"2\",\"Formato\":\"21 x 27 cm\",\"P\\u00e1ginas\":\"160\",\"Estuche\":\"Caja imantada\"}', NULL, NULL, '2026-07-12 07:42:57', '2026-07-12 07:42:57'),
(72, 'LEER Y VER MI PEQUEÑO MUNDO', NULL, 'Una obra con imágenes didácticas, como representaciones de la realidad, acompañan los contenidos educativos, que atesoran información variada, activan emociones, pueden despertar críticas, comparaciones, clasificaciones y un sinfín de ideas nuevas.', '{\"Tomos\":\"2\",\"Formato\":\"21 x 27 cm\",\"P\\u00e1ginas\":\"64\",\"Estuche\":\"Caja imantada\"}', NULL, NULL, '2026-07-12 07:51:56', '2026-07-12 07:51:56'),
(73, 'LEER Y VER CUERPO HUMANO', NULL, 'Una obra que nos invita a realizar un recorrido fascinante por el interior de nuestro cuerpo. Contiene información completa y actualizada, acompañada de mapas conceptuales e ilustraciones basadas en trabajos de importantes anatomistas e investigadores.', '{\"Tomos\":\"2\",\"Formato\":\"21 x 27 cm\",\"P\\u00e1ginas\":\"160\",\"Estuche\":\"Caja imantada\"}', NULL, NULL, '2026-07-12 07:53:26', '2026-07-12 07:53:26'),
(74, 'LEER Y VER BIOLOGÍA Y MEDIO AMBIENTE', NULL, 'Una obra que les permitirá recorrer los conceptos principales sobre el estudio de los seres vivos y su entorno. Como principal recurso, la obra incluye diez impactantes imágenes integradoras en las que, a través de ilustraciones y fotografías a todo color.', '{\"Tomos\":\"1\",\"Formato\":\"21 x 27 cm\",\"P\\u00e1ginas\":\"160\",\"Estuche\":\"Caja imantada\"}', NULL, NULL, '2026-07-12 07:54:56', '2026-07-12 07:54:56'),
(75, 'TALLER DE MANUALIDADES', NULL, 'Una obra maravillosa llena de actividades y ejercicios para realizar en casa, en el jardín o en los primeros años de la escuela primaria. Ideal para desarrollar y mejorar la motricidad fina. Estimulación del sentido estético de los niños. Con actividades que motivan la autonomía, y otras que permiten el acompañamiento de los padres o maestros.', '{\"Tomos\":\"1\",\"Formato\":\"28 x 31 cm\",\"P\\u00e1ginas\":\"212\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 07:55:57', '2026-07-12 07:55:57'),
(76, 'NUEVA PLÁSTICA DE PRIMARIA', NULL, 'Esta obra abarca actividades prácticas desde los 3 hasta los 10 años, para cada momento del año, con instrucciones claras y sencillas. La obra está acompañada de ilustraciones paso a paso para desarrollar diversas habilidades de los niños, y también para que los padres y los maestros puedan acompañar las actividades. Proyectos con materiales fáciles de conseguir y reciclables.', '{\"Tomos\":\"1\",\"Formato\":\"28 x 31 cm\",\"P\\u00e1ginas\":\"256\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 07:57:56', '2026-07-12 07:57:56'),
(77, 'MÚSICA PARA NIÑOS', NULL, 'Esta obra está pensada para que los niños entre 6 y 13 años se introduzcan en el mundo de la música y su historia. El libro recorre la historia del desarrollo de la música, desde las primeras expresiones musicales del hombre primitivo hasta los modernos electrónicos.\r\nSi bien está diseñado para posibilitar el aprendizaje del niño en forma autónoma, este libro puede ser utilizado como instrumento de enseñanza para padres y docentes.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 30 cm\",\"P\\u00e1ginas\":\"300\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 07:59:27', '2026-07-12 07:59:27'),
(78, 'APRENDAMOS Y JUGUEMOS CON LA MÚSICA', NULL, 'Esta obra ha sido especialmente pensada para que los niños se introduzcan en el mundo de la música. Está escrita de forma amena y divertida, con datos curiosos y actividades para que construyan sus propios instrumentos; de manera autónoma o con la ayuda de padres o maestros.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 30 cm\",\"P\\u00e1ginas\":\"292\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 08:00:22', '2026-07-12 08:00:22'),
(79, 'EXPERIMENTA CON LA CIENCIA Y LA TECNOLOGÍA', NULL, 'Este libro de experimentos demuestra muchos de los avances y descubrimientos que han tenido un impacto en nuestras vidas. La técnica de hacerse preguntas y tratar de responderlas a través de la observación y la experimentación es importante para la ciencia.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 30 cm\",\"P\\u00e1ginas\":\"291\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 08:01:21', '2026-07-12 08:01:21'),
(80, 'EDUCACIÓN DE ADULTOS', NULL, 'Actividades y recursos para el aprendizaje de jóvenes y adultos. Lengua, Matemática, Ciencias Naturales, Ciencias Naturales.', '{\"Tomos\":\"1\",\"Formato\":\"18 x 28 cm\",\"P\\u00e1ginas\":\"384\",\"Tapa\":\"Dura\",\"Cuadernillos\":\"6\"}', NULL, NULL, '2026-07-12 08:02:42', '2026-07-12 08:02:42'),
(81, 'ACTIVIDADES PARA LA ESTIMULACIÓN ADECUADA', NULL, 'En esta obra encontrará más de 200 actividades para ayudar a los niños a tener conciencia de sus cuerpos, manifestar sus emociones, comunicarse, desarrollar su creatividad y poco a poco, convertirse en autónomos. Una guía especial para padres, maestros, abuelos o niñeras.', '{\"Tomos\":\"1\",\"Formato\":\"27 x 30 cm\",\"P\\u00e1ginas\":\"127\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 18:33:35', '2026-07-12 18:33:35'),
(82, 'DICCIONARIO ESCOLAR DE LA LENGUA ESPAÑOLA', NULL, 'Este diccionario incluye:\r\n\r\n-Regiones geográficas.\r\n\r\n-Fundaciones de ciudades capitales.\r\n\r\n-Aborígenes de nuestro país.\r\n\r\n-Símbolos patrios.\r\n\r\n-Todos los escudos de la Nación Argentina.\r\n\r\n-Presidentes.\r\n\r\n-Fechas patrias.\r\n\r\n-Datos de todas las provincias.\r\n\r\n-Efemérides.\r\n\r\n-Términos gramaticales.', '{\"Tomos\":\"1\",\"Formato\":\"14 x 20 cm\",\"P\\u00e1ginas\":\"466\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 18:35:09', '2026-07-12 18:35:09'),
(83, 'DICCIONARIO POCKET INGLÉS - ESPAÑOL ESPAÑOL - INGLÉS', NULL, 'Este diccionario incluye:\r\n-Notas sobre gramática elemental.\r\n-Verbos irregulares más usuales.\r\n-Frases básicas en inglés que se pueden usar en conversaciones diarias y en situaciones específicas.\r\n-Verbos.\r\n-Abreviaturas.', '{\"Tomos\":\"1\",\"Formato\":\"14 x 20\",\"P\\u00e1ginas\":\"466\",\"Tapa\":\"R\\u00fastica\"}', NULL, NULL, '2026-07-12 18:36:40', '2026-07-12 18:36:40'),
(84, 'CIENCIA EXPRÉS CIENCIA FÁCIL PARA NIÑOS', NULL, '¡LA CIENCIA ES DIVERTIDA! DESCÚBRELO EN ESTA CAJA LLENA DE EXPERIMENTOS.\r\n\r\nCiencia exprés una obra que pone al alcance de los niños experimentos realmente fáciles y seguros, que les permitirán explorar nociones básicas de Física, Química, magnetismo y mucho más.\r\n\r\nIncluye 5 láminas formato 52x46cms.', '{\"Tomos\":\"5\",\"Formato\":\"24 x 28 cm\",\"P\\u00e1ginas\":\"32 por tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\"}', NULL, NULL, '2026-07-12 18:40:18', '2026-07-12 18:40:18'),
(85, 'CIENCIA PARA EL ASOMBRO', NULL, 'Te ayudamos a enseñar ciencias naturales y ambientales.\r\nNuestra Caja N 1 ofrece materiales educativos para favorecer el desarrollo cognitivo de los niños.\r\nLibro con 50 actividades prácticas, ideas innovadoras y materiales complementarios.\r\n\r\n25 Láminas desplegables.\r\n\r\n50 Fichas con las secuencias didácticas completas de cada una de las actividades prácticas.\r\nTemas incluidos:\r\n\r\nEl aire, las plantas, el ser humano, el agua, el sonido, nuestro planeta, los materiales que nos rodean... y mucho más.', '{\"Tomos\":\"1\",\"Formato\":\"21 x 28 cm\",\"P\\u00e1ginas\":\"200\",\"Estuche\":\"Caja de cart\\u00f3n\",\"L\\u00e1minas\":\"25\",\"Fichas\":\"50\"}', NULL, 'https://youtu.be/feOpeYDMrf8', '2026-07-12 18:44:14', '2026-07-12 18:44:44'),
(86, 'VOCACIÓN DE MAESTRA', NULL, 'Temas para la práctica educativa.\r\n \r\nSoluciones pedagógicas en el aula en tomos con distintas áreas de aprendizaje para NIVEL INICIAL Y PRIMER CICLO.', '{\"Tomos\":\"6\",\"Formato\":\"16 x 24 cm\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 18:51:37', '2026-07-12 18:51:37'),
(87, 'EL GRAN LIBRO DE LA MAESTRA JARDINERA', NULL, 'Guía práctica para la enseñanza en el nivel inicial.\r\n \r\n-Definición y Estructura\r\n-Teorías de aprendizaje\r\n-La educación inicial\r\n-La formación social\r\n-La comunidad Educativa, roles y funciones\r\n-Organización de momentos del año\r\n-El espacio\r\n-Planificación del trabajo\r\n-Evaluación\r\n-Concepción del juego\r\n-Psicología evolutiva\r\n-Desarrollo madurativo\r\n-El lenguaje oral\r\n-Trastornos del desarrollo\r\n-Integración escolar\r\n-Ingreso del niño con dificultades\r\n-Lectoescritura\r\n-Actividades\r\n-El informe\r\n-Ideas para planificar\r\n-Actividades grafo plásticas', '{\"Tomos\":\"1\",\"Formato\":\"19 x 26 cm\",\"P\\u00e1ginas\":\"1074\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 18:53:49', '2026-07-12 18:53:49'),
(88, 'EL LENGUAJE ORAL Y ESCRITO', NULL, 'Se incluye en este libro amplio material de trabajo para el entrenamiento de las funciones lingüísticas y la conciencia fonológica, en distintos niveles de complejidad, para ser usados en el nivel inicial y en la escuela primaria. Actividades orales, actividades lúdicas, ejercicios en imprenta y en cursiva, fichas de trabajo, todo listo para ser usado en el aula. Sigamos conociendo el cerebro de los niños para brindarles mejores oportunidades de aprendizaje y mejorar así su calidad de vida.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"536\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 18:55:46', '2026-07-12 18:55:46'),
(89, 'De maternal a preescolar DESARROLLO INFANTIL', NULL, 'Esta obra abarca una variedad de temas y actividades haciendo un seguimiento en la Estimulación Temprana, Psicología Evolutiva y en la Inteligencia Múltiples.\r\n-Áreas de desarrollo madurativo.\r\n-Caracteristicas del desarrollo por mes.\r\n-Masajes y gimnasia para niños hasta 18 meses.\r\n-Actividades pedagógicas.\r\n-Funciones motoras.\r\n-Desarrollo emocional y social.\r\n-Funciones Intelecto -Cognitivas.\r\n-Clasificación de las Inteligencias.\r\n-Orientación Vocacional.', '{\"Tomos\":\"1\",\"Formato\":\"19 x 26 cm\",\"P\\u00e1ginas\":\"536\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 18:59:38', '2026-07-12 18:59:38'),
(91, 'CONSTRUIR CONOCIMIENTO DESDE EL PATIO', NULL, 'Actividades para las clases de EDUCACIÓN FÍSICA.\r\nEste libro contiene herramientas indispensables para trabajar todas las disciplinas desde la Educación Física. Tanto para Nivel Inicial como en Escuela Primaria, Matemática, Práctica del Lenguaje, Ciencias Sociales y Ciencias Naturales. Presenta una original manera de enseñar a sus chicos y es, jugando, para esto es necesario tener en cuenta el cuerpo, revalorizarlo y tomar conciencia de él.\r\nActividades especiales para cada disciplina y un apéndice para niños con capacidades diferentes.', '{\"Tomos\":\"1\",\"Formato\":\"19 x 26 cm\",\"P\\u00e1ginas\":\"460\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:01:59', '2026-07-12 19:01:59'),
(92, 'Guía práctica de la PSICOPEDAGOGÍA PARA EL AULA', NULL, 'Conoceremos las incumbencias del trabajo de los docentes de Educación común y especial, la actuación de los equipos de orientación escolar, el rol del maestro integrador y del acompañamiento terapéutico, la organización y puesta en marcha de un proyecto de orientación educativo. Conoceremos los Trastornos del desarrollo de la infancia y su abordaje terapéutico y escolar, los trastornos de aprendizaje, los trastornos de conducta, el manejo de la disciplina y los valores en el aula.', '{\"Tomos\":\"1\",\"Formato\":\"17 x 24 cm\",\"P\\u00e1ginas\":\"624\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:04:22', '2026-07-12 19:04:22'),
(93, 'SÍNDROME DE DOWN Y DISCAPACIDAD INTELECTUAL', NULL, 'Una obra destinada a padres y docentes de niños con Síndrome de Down o con Discapacidad Intelectual. Incluye definiciones, criterios diagnósticos, características, evolución en el desarrollo, iniciación en la educación sistemática e integración escolar; se plantean sugerencias y modelos de actividades escolares de todas las áreas.', '{\"Tomos\":\"1\",\"Formato\":\"17 x 24 cm\",\"P\\u00e1ginas\":\"360\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:05:51', '2026-07-12 19:05:51'),
(94, 'Soluciones pedagógicas para el TDA-H', NULL, 'Trastorno por déficit de atención con o sin hiperactividad\r\n- Trastorno por Déficit de Atención\r\n- Caracterización del TDA/TDAH\r\n- La Hiperactividad\r\n- Bases Neurobiológicas del TDA/TDH\r\n- Tratamiento farmacológico\r\n- Adolescencia y Adultos con TDA /TDAH\r\n- Trastornos asociados\r\n- Diagnóstico\r\n- El tratamiento en niños\r\n- Instrucciones de trabajo con un niño', '{\"Tomos\":\"1\",\"Formato\":\"17 x 24 cm\",\"P\\u00e1ginas\":\"254\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:07:27', '2026-07-12 19:07:27'),
(95, 'TRASTORNOS ESCOLARES', NULL, 'Detección - Diagnóstico y Tratamiento\r\n \r\nEs una obra donde los trabajadores de la educación encontrarán una amplia gama de trastornos y los síntomas que presentan los niños con dificultades escolares. La propuesta de esta obra consiste en derribar las barreras del desconocimiento, la culpa y las acusaciones, para centrar la labor en la gran responsabilidad docente: el niño problema y su aprendizaje dentro de un grupo de trabajo compartido.', '{\"Tomos\":\"1\",\"Formato\":\"17 x 24 cm\",\"P\\u00e1ginas\":\"410\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:09:17', '2026-07-12 19:09:17'),
(96, 'TGD TES/TEA EN LA ESCUELA', NULL, 'Una obra fundamental para docentes, maestros integradores, Equipos de orientación escolar y demás acompañantes donde encontrarán un vasto compendio de información adecuada a la realidad escolar.\r\n\r\n\r\n\r\nDefinición de TGD/TEA y TES/TP.\r\nElementos diagnósticos y marcadores para una detección precoz.\r\nLineamientos terapéuticos para cada patología.\r\nProcedimientos a realizar en la Escuela y en la Escuela especial.\r\nIntegración escolar y planificación de acciones directas.\r\nTeórico-práctico para trabajar con los alumnos.', '{\"Tomos\":\"1\",\"Formato\":\"19 x 26 cm\",\"P\\u00e1ginas\":\"380\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:10:57', '2026-07-12 19:10:57'),
(97, 'ENCICLOPEDIA GUADAL NIVEL INICIAL', NULL, 'Una enciclopedia para nivel inicial y primer ciclo con contenidos elaborados por el Ministerio de Educación de la Nación. Esta presenta cuatro áreas (Lengua, Matemática, Ciencias Naturales y Ciencias Sociales), una antología literaria, efemérides y un mini atlas. Incluye CD Interactivo con actividades y juegos.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"512\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:12:53', '2026-07-12 19:12:53'),
(98, 'PSICOLOGÍA PARA TODOS', NULL, 'GUÍA COMPLETA PARA EL CRECIMIENTO PERSONAL\r\n\r\nUna obra creada por un equipo de reconocidos profesionales, aporta una visión clara y completa de la Psicología contemporánea, entendida como disciplina científica y práctica.\r\n\r\nEl objetivo ha sido ofrecer un texto que reúna el enfoque riguroso con una amplia y cálida perspectiva humana, utilizando un lenguaje accesible que ayude al lector a conocerse a sí mismo y a los demás.', '{\"Tomos\":\"4\",\"Formato\":\"18 x 25 cm\",\"P\\u00e1ginas\":\"936\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:15:34', '2026-07-12 19:15:34'),
(99, 'NUEVO OCÉANO UNO COLOR DICCIONARIO ENCICLOPÉDICO', NULL, 'Una obra completamente renovada, actualizada y puesto al día, ofrece el conocimiento básico de cualquier materia, concepto o disciplina.\r\n\r\n- 83000 artículos de léxico y enciclopédicos, pertenecientes a todos los temas del saber universal.\r\n\r\n- Más de 210000 acepciones.\r\n\r\n- Más de 8000 ilustraciones: fotografías, dibujos, esquemas, gráficos, tablas, mapas geográficos y mapas temáticos.\r\n\r\n- Mapa de situación bandera y tabla de datos de todos los países del mundo.\r\n\r\n- Atlas universal creado especialmente para esta obra con las más modernas técnicas cartográficas.\r\n\r\n- Transvisiones exclusivas.\r\n\r\n- Exclusivo uñero localizador.\r\n\r\n- CD-ROM y contenidos con accesos ON LINE.', '{\"Tomos\":\"1\",\"Formato\":\"16 x 23 cm\",\"P\\u00e1ginas\":\"1816\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:17:16', '2026-07-12 19:17:16'),
(100, 'GRAN ENCICLOPEDIA ESTUDIANTIL TEMÁTICA ILUSTRADA', NULL, 'Una obra que contempla los principales temas que exigen las currículas educativas actuales.\r\n\r\nBiología y Ciencias - Física - Ecología y Medio Ambiente – Química - Cuerpo Humano y Salud – Tecnología - Formación Ciudadana – Geografía - Gramática y Ortografía - Astronomía y Geología - Inglés - Antiguas Civilizaciones - Matemática - Historia Universal - Algebra\r\n\r\nDISFRUTA DE CONTENIDOS INTERACTIVOS EN LA APLICACIÓN CLASA MÁS Y CLASA DIGITAL.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"1024\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Dura\",\"Aplicaci\\u00f3n\":\"Clasa +\",\"Incluye\":\"Clasa Digital\"}', NULL, 'https://www.youtube.com/shorts/itcyQ3tBg7o?feature=share', '2026-07-12 19:20:28', '2026-07-12 19:20:55'),
(101, 'LA CAJA MÁGICA DE MIGUELITO', NULL, 'Miguelito es un pequeño mago de 8 años que junto con su simpático ayudante Varita, un astuto perro callejero, enseña sus sorprendentes trucos a todos los niños que quieran descubrir los apasionantes misterios de la magia.\r\nEn el libro de magia de Miguelito encontrarás los mejores trucos con monedas, naipes, dados, pañuelos y otros objetos que puedes encontrar en tu casa.\r\nSu gran secreto está guardado en su libro mágico, un valioso manual de magia que Miguelito heredó de su abuelo, el gran mago León, del que se decía, poseía un gran don...', '{\"Tomos\":\"1\",\"Formato\":\"21 x 29 cm\",\"P\\u00e1ginas\":\"190\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Varita m\\u00e1gica\"}', NULL, NULL, '2026-07-12 19:29:20', '2026-07-12 19:29:20'),
(102, 'PATITO FEO - PIZARRA MÁGICA', NULL, 'Hermoso cuento para los mas pequeños. Incluyen preguntas y respuestas. Narrado en imprenta mayúscula. Incluye una pizarra mágica para dibujar.', '{\"Tomos\":\"1\",\"Formato\":\"21 x 18 cm\",\"P\\u00e1ginas\":\"8\"}', NULL, NULL, '2026-07-12 19:34:16', '2026-07-12 19:34:16'),
(103, 'LOS TRES CHANCHITOS - PIZARRA MÁGICA', NULL, 'Hermoso cuento para los mas pequeños. Incluyen preguntas y respuestas. Narrado en imprenta mayúscula. Incluye una pizarra mágica para dibujar.', '{\"Tomos\":\"1\",\"Formato\":\"21 x 18 cm\",\"P\\u00e1ginas\":\"8\"}', NULL, NULL, '2026-07-12 19:35:19', '2026-07-12 19:35:19'),
(104, 'MAXI BOX MINIONS - MI VILLANO FAVORITO', NULL, 'Presentamos cuatros historias de personajes queridos y reconocidos por los chicos con las ilustraciones de siempre. Adicionalmente, el nuevo tomo, de mayor formato, se expande en distintas secciones de actividades para aprender y disfrutar: comprensión lectora, habilidades verbales, lógica matematica, aprendizaje motriz y juegos para disfrutar solos o acompañados.', '{\"Tomos\":\"5\",\"Formato\":\"13 x 18 cm y 27 x 37 cm\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:37:12', '2026-07-12 19:37:12'),
(105, 'MAXI BOX MICKEY SOBRE RUEDAS', NULL, '¡Nueva presentación con más actividades para aprender y disfrutar! Acompaña a Mickey a sus amigos a vivir las historias más entretenidas. Trabaja comprensión lectora, habilidades verbales, lógica matemática, aprendizaje motriz y juegos para disfrutar solos o acompañados.', '{\"Tomos\":\"5\",\"Formato\":\"13 x 18 cm y 27 x 37 cm\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:38:59', '2026-07-12 19:38:59'),
(106, 'MAXI BOX CARS', NULL, '¡Divertirte con el mundo de Cars! Esta hermosa colección contiene todas sus páginas, pizarras mágicas, donde podrás divertirte leyendo, dibujando, escribiendo y despegando tu imaginación y creatividad, ¡para que aprender sea más divertido que nunca!', '{\"Tomos\":\"5\",\"Formato\":\"13 x 18 cm y 27 x 37 cm\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:41:24', '2026-07-12 19:41:24'),
(107, 'CUENTOS AMISTOSOS - MY LITTLE PONY', NULL, 'Bienvenidos al mundo de My Little Pony. A través de los 6 ponis conocerás la magia de la amistad. Los amigos compartirán amabilidad, lealtad, honestidad, generosidad, risa y magia los cuales apuntan a niños y niñas de todo el mundo.', '{\"Tomos\":\"8\",\"Formato\":\"13 x 18 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n con pop up\"}', NULL, NULL, '2026-07-12 19:43:44', '2026-07-12 19:43:44'),
(108, 'CUENTOS TENEBROSOS - MONSTER HIGH', NULL, 'Una colección con las muñecas más aterradoras y famosas entre las niñas de hoy en día. Entra en sus mundos y juega con las actividades de cada cuento las cuales apuntan al desarrollo de distintas habilidades.', '{\"Tomos\":\"8\",\"Formato\":\"13 x 18 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n con pop up\"}', NULL, NULL, '2026-07-12 19:45:52', '2026-07-12 19:45:52'),
(109, 'AVIONES - CUENTOS INTRÉPIDOS', NULL, 'Esta obra cuenta las historias de un avión que sueña con ser un gran corredor de carreras, pero le tiene miedo a las alturas. Cada libro tiene una actividad para reforzar valores y habilidades.', '{\"Tomos\":\"8\",\"Formato\":\"13 x 18 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:47:08', '2026-07-12 19:47:08'),
(110, 'CUENTOS EXPLORADORES - DORA LA EXPLORADORA', NULL, 'Acompaña a Dora la exploradora a conocer la importancia de cuidar el medio ambiente. Utiliza las actividades de cada cuento para reforzar las enseñanzas.', '{\"Tomos\":\"8\",\"Formato\":\"13 x 18 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra m\\u00e1gica\"}', NULL, NULL, '2026-07-12 19:48:30', '2026-07-12 19:48:30');
INSERT INTO `libros` (`id`, `titulo`, `subtitulo`, `descripcion`, `caracteristicas`, `video_archivo`, `video_url`, `created_at`, `updated_at`) VALUES
(111, 'CUENTOS INVENCIBLES - IRON MAN', NULL, 'Una fascinante obra para que puedas acompañar a este superhéroe y sus compañeros Los Avengers a combatir el mal. Cada cuento contiene actividades para el desarrollo de distintas habilidades.', '{\"Tomos\":\"8\",\"Formato\":\"13 x 18 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra m\\u00e1gica\"}', NULL, NULL, '2026-07-12 19:50:32', '2026-07-12 19:50:32'),
(112, 'REINAS, HADAS Y PRINCESAS', NULL, 'Las mejores historias sobre reinas, hadas y princesas, bellamente ilustradas. Cada cuento está acompañado con actividades.', '{\"Tomos\":\"8\",\"Formato\":\"13 x 18 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n con pop up\"}', NULL, NULL, '2026-07-12 19:52:19', '2026-07-12 19:52:19'),
(113, 'LITERALMENTE EMOCIONES Y VALORES PARA LA CONVIVENCIA', NULL, 'Literatura y mentes aprenden jugando.\r\n \r\nLas tipografías utilizadas son amigables para lectores con dislexia.', '{\"Tomos\":\"2\",\"Formato\":\"26 x 19 cm\",\"P\\u00e1ginas\":\"262\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:54:21', '2026-07-12 19:54:21'),
(114, 'LITERALMENTE POESÍAS', NULL, 'Literatura y mentes aprenden jugando.\r\nConjunto de poesías que toma a los personajes más significativos de los cuentos tradicionales, incorporándoles valores cotidianos y acercándole a los niños la literatura de todos los tiempos, en una forma ágil y de fácil lectura.', '{\"Tomos\":\"2\",\"Formato\":\"26 x 19 cm\",\"P\\u00e1ginas\":\"262\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-12 19:55:28', '2026-07-12 19:55:28'),
(115, 'LOS DUENDES DEL SUR - NÚMEROS', NULL, 'Una colección con cuentos de los duendes del sur donde los chicos aprenderán de forma rápida los NÚMEROS, con actividades didácticas, un puzzle y un CD con imágenes para imprimir y para colorear.\r\nLos duendes del sur viven en una aldea perdida de la Patagonia, en los bosques de un hermoso valle, al pie de una gran montaña y de un ancho río. Algunos visitantes del valle aseguran que los ha visto en la zona de \"El Bolsón\", cerca del cerro Piltriquitróm y del Río Azul.', '{\"Tomos\":\"1\",\"Formato\":\"30 x 43 cm\",\"P\\u00e1ginas\":\"18\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Rompecabezas 35 piezas\"}', NULL, NULL, '2026-07-12 20:05:28', '2026-07-12 20:05:28'),
(116, 'MONSTER HIGH EN 3D - ESPECTRACULARES HISTORIAS', NULL, '¡Todos los personajes de la serie en dos tomos sorprendentes!\r\n- Manualidades Monstruosas.\r\n- Màs de 60 stickers.\r\n- Más de 100 esténciles.\r\n- LENTES 3D para usar con la sección de Posters 3D.', '{\"Tomos\":\"2\",\"Formato\":\"27 x 38 cm y 26 x 29 cm\",\"Incluye\":\"Lentes 3D\"}', NULL, NULL, '2026-07-13 00:38:10', '2026-07-13 00:38:10'),
(117, 'STAR WARS', NULL, 'Conoce el universo de StarWars, en el que ya hace mucho tiempo, en una galaxia muy, muy lejana, caballeros jedi, princesas, pilotos, guerreros y robots libraron diversas batallas para restaurar la libertad.\r\nTítulos:\r\nEL RETORNO DEL JEDI, UNA NUEVA ESPERANZA, EL IMPERIO CONTRATACA.', '{\"Tomos\":\"3\",\"Formato\":\"27 x 37 cm\",\"P\\u00e1ginas\":\"24 cada tomo\"}', NULL, NULL, '2026-07-13 00:40:59', '2026-07-13 00:40:59'),
(118, 'MAXI CUENTOS DE COLORES - Jake y los piratas del país de nunca jamás', NULL, 'Te abrimos las puertas para ingresar al maravilloso mundo de Jake y sus amigos. Aprenderás valores y desarrollarás capacidades sin perder un minuto de diversión. Con todas sus páginas pizarra mágicas podrás jugar una y otra vez.', '{\"Tomos\":\"1\",\"Formato\":\"38 x 48 cm\",\"P\\u00e1ginas\":\"20\",\"Incluye\":\"Marcador con borrador\"}', NULL, NULL, '2026-07-13 00:42:39', '2026-07-13 00:42:39'),
(119, 'MAXI CUENTOS DE COLORES – LOS PITUFOS', NULL, 'Te abrimos las puertas para ingresar al maravilloso mundo de Los Pitufos. Aprenderás valores y desarrollaras capacidades sin perder un minuto de diversión. Con todas sus páginas pizarra mágica podrás jugar una y otra vez.', '{\"Tomos\":\"1\",\"Formato\":\"38 x 48 cm\",\"P\\u00e1ginas\":\"20\",\"Incluye\":\"Marcador con borrador\"}', NULL, NULL, '2026-07-13 00:43:50', '2026-07-13 00:43:50'),
(120, 'MAXI CUENTOS DE COLORES – CAROL', NULL, 'Te abrimos las puertas para ingresar al mundo de CAROL. Aprenderás valores y desarrollaras capacidades sin perder un minuto de diversión. Con todas sus páginas pizarra mágica podrás jugar una y otra vez.', '{\"Tomos\":\"1\",\"Formato\":\"38 x 48 cm\",\"P\\u00e1ginas\":\"20\",\"Incluye\":\"Marcador con borrador\"}', NULL, NULL, '2026-07-13 00:45:00', '2026-07-13 00:45:00'),
(121, 'MAXI CUENTOS DE COLORES – TRANSFORMERS', NULL, 'Acompaña a Bummblebee y sus compañeros en busca de los Decepticons. Aprenderás valores y desarrollarás habilidades sin perder un minuto de diversión. Con todas sus páginas pizarra mágica podrás jugar una y otra vez.', '{\"Tomos\":\"1\",\"Formato\":\"38 x 48 cm\",\"P\\u00e1ginas\":\"20\",\"Incluye\":\"Marcador con borrador\"}', NULL, NULL, '2026-07-13 00:46:09', '2026-07-13 00:46:09'),
(122, 'MULTICUENTOS DE COLORES MARAVILLOSOS PARA LOS MÁS CHIQUITOS (Azul)', NULL, 'Cuentos con actividades. Libro ideal para el desarrollo intelectual y motriz de los niños.\r\nActividades de expresión corporal y coordinación.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"112\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-13 00:47:58', '2026-07-13 00:47:58'),
(123, 'MULTICUENTOS DE COLORES  PARA LOS MÁS CHIQUITOS (Verde)', NULL, 'Cuentos con actividades. Libro ideal para el desarrollo intelectual y motriz de los niños.\r\nEstimula la formación de hábitos y la capacidad de razonamiento.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"112\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-13 00:49:33', '2026-07-13 00:49:33'),
(124, 'MULTICUENTOS DE COLORES - BEBESAURIO (Verde)', NULL, 'Cuentos para descubrir y aprender con el bebé dinosaurio.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"112\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-13 00:50:35', '2026-07-13 00:50:35'),
(125, 'MULTICUENTOS DE COLORES - BEBESAURIO (Rojo)', NULL, 'Cuentos para descubrir y aprender con el dinosaurio adulto.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"112\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-13 00:51:35', '2026-07-13 00:51:35'),
(126, 'MULTICUENTOS DE COLORES - DISNEY JUNIORS VIOLETA', NULL, 'Una obra para entrar al maravilloso mundo de Disney y sus personajes.\r\nTítulos:\r\nVampirina, Mickey Mouse, Enredados, Toy Story, Princesita Sofia, La guardia del león, Doctora Juguetes y Minnie.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"112\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-13 00:53:36', '2026-07-13 00:53:36'),
(127, 'SERIE AMARILLA - Mickey', NULL, 'Increíble colección de Mickey para que los más chicos jueguen y aprendan junto a sus personajes favoritos. Los cuentos estimulan la solidaridad, importancia de los deportes, estimula la curiosidad y invita al conocimiento de las figuras geométricas. Actividades en todos los tomos.', '{\"Tomos\":\"4\",\"Formato\":\"13 x 18 cm\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra m\\u00e1gica y marcador\"}', NULL, NULL, '2026-07-13 00:55:15', '2026-07-13 00:55:15'),
(128, 'UN MARAVILLOSO MUNDO DE PRINCESAS', NULL, '¿Sueñas con ser una princesa? Abre este libro y comienza a recorrer el mundo junto a las princesas. Incluye el juego “Buscando con Princesas”.', '{\"Tomos\":\"1\",\"Formato\":\"30 x 40 cm\",\"P\\u00e1ginas\":\"60\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Stickers\"}', NULL, NULL, '2026-07-13 00:56:36', '2026-07-13 00:56:36'),
(129, 'EL MÁGICO MUNDO DE LAS PRINCESAS  (SERIE ZAFIRO)', NULL, 'Una colección para las chicas, con aventuras de príncipes, castillos y un mundo de fantasías. Incluye CD con cuentos animados y 80 rompecabezas para armar en la PC.\r\n\r\n Títulos:\r\n\r\nPrincesa Micaela, Princesa Ailén, Princesa Noelia, Princesa Daiana, Princesa Sofía, Princesa Celeste, Princesa Oriana, Princesa Jésica.', '{\"Tomos\":\"8\",\"Formato\":\"15 x 15 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n con pop up luminoso\",\"Incluye\":\"Pizarra m\\u00e1gica y marcador\"}', NULL, NULL, '2026-07-13 01:01:51', '2026-07-13 01:01:51'),
(130, 'MI PRIMERA ENCICLOPEDIA DE JARDÍN', NULL, 'Es una obra especialmente creada para entretener a los niños, fomentando la lectura desde sus primeros pasos. Les enseña las nociones básicas a través de un pequeño cuento ilustrado. ¡Un libro que educa y entretiene!', '{\"Tomos\":\"1\",\"Formato\":\"28 x 38 cm\",\"P\\u00e1ginas\":\"20\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Anteojos 3D, pizarra y marcador\"}', NULL, NULL, '2026-07-13 01:03:24', '2026-07-13 01:03:24'),
(131, 'CUENTOS INOLVIDABLES DE CARS', NULL, 'En esta obra junto a Rayo McQueen, aprenderemos que la velocidad, las carreras, los premios y los aplausos no poseen ningún valor si no tenemos un amigo verdadero. En un práctico y simpático formato de valija.\r\n\r\nTítulos:\r\n\r\nLa gran copa, MI hogar Radiador Springs, El gran Mate, Equipo de rescate, Mate de viaje, Velocidad Máxima.', '{\"Tomos\":\"6\",\"Formato\":\"9 x 9 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra m\\u00e1gica y marcador, escenarios y personajes para recortar\"}', NULL, NULL, '2026-07-13 01:05:06', '2026-07-13 19:33:53'),
(132, 'CUENTOS INOLVIDABLES DE PRINCESAS DISNEY', NULL, 'Una colección pensada para que las más pequeñas acompañen a estas valientes heroínas. En un práctico y simpático formato de valija.\r\n\r\n \r\n\r\nTítulos:\r\n\r\nBlanca Nieves, Ariel, Jasmín, Aurora, Bella, Cenicienta.', '{\"Tomos\":\"6\",\"Formato\":\"9 x 9 cm\",\"P\\u00e1ginas\":\"12 caca tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra y marcador, escenarios y personajes\"}', NULL, NULL, '2026-07-13 01:06:21', '2026-07-13 01:06:21'),
(133, 'COLECCIÓN CHILLONES DISNEY CLASSIC', NULL, 'Divertidas historias para que los más pequeños disfruten junto a los personajes clásicos de Disney. Cada libro contiene la cara del personaje con un sonido.\r\n\r\n \r\n\r\nTítulos:\r\nEl jardín de Mickey, Las vacaciones de Minnie, Los amigos de WinniePooh, Un día con Tigger.', '{\"Tomos\":\"4\",\"Formato\":\"15 x 15 cm\",\"P\\u00e1ginas\":\"10 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 01:08:36', '2026-07-13 01:08:36'),
(134, 'MI LIBRO GIGANTE DE CUENTOS PEQUEÑITOS', NULL, 'Una selección de tiernos cuentos clásicos de ayer, hoy y siempre, que deleitarán a los más pequeños de la familia. Acompaña la narración de cada relato un divertido rompecabezas gigante, que ayudará a favorecer el desarrollo de destrezas motrices y de competencias como el pensamiento lógico y la memoria.\r\n\r\nTítulos:\r\n\r\nLos tres cerditos, El patito feo, El gato con botas, Pinocho.', '{\"Tomos\":\"1\",\"Formato\":\"33 x 46 cm\",\"P\\u00e1ginas\":\"8\",\"Rompecabezas\":\"4 de 30 piezas\"}', NULL, NULL, '2026-07-13 01:12:49', '2026-07-13 01:12:49'),
(135, 'MI LIBRO GIGANTE DE CUENTOS FANTÁSTICOS', NULL, 'Las más divertidas aventuras de todos los tiempos cuidadosamente seleccionadas y adaptadas para los más pequeños. Cada historia es acompañada por un rompecabezas gigante, que ayudará a favorecer el desarrollo de destrezas motrices y de competencias como el pensamiento lógico y la memoria.\r\n\r\n \r\n\r\nTítulos:\r\n\r\nAladino y la lámpara maravillosa, El flautista de Hamelín, Las habichuelas mágicas, Peter Pan.', '{\"Tomos\":\"1\",\"Formato\":\"33 x 46 cm\",\"P\\u00e1ginas\":\"8\",\"Rompecabezas\":\"4 de 30 piezas\"}', NULL, NULL, '2026-07-13 01:14:06', '2026-07-13 01:14:06'),
(136, 'MI LIBRO GIGANTE DE CUENTOS MARAVILLOSOS', NULL, 'Una selección de encantadoras historias de princesas que deleitarán a sus pequeñas lectoras. Cada relato es acompañado por un divertido rompecabezas gigante, que ayudará a favorecer el desarrollo de destrezas motrices y de competencias como el pensamiento lógico y la memoria.', '{\"Tomos\":\"1\",\"Formato\":\"33 x 46 cm\",\"P\\u00e1ginas\":\"8\",\"Rompecabezas\":\"4 de 30 piezas\"}', NULL, NULL, '2026-07-13 01:15:35', '2026-07-13 01:15:35'),
(137, 'MI LIBRO GIGANTE DE CUENTOS MUÑEQUITAS', NULL, 'Una selección de mágicas historias de princesas, que deleitarán a sus pequeñas lectoras. Acompaña la narración de cada relato un divertido rompecabezas gigante, que ayudará a favorecer el desarrollo de destrezas motrices y de competencias como el pensamiento lógico y la memoria.\r\n\r\n Títulos:\r\n\r\nCenicienta, Blanca Nieves, La bella durmiente, Caperucita Roja.', '{\"Tomos\":\"1\",\"Formato\":\"33 x 46 cm\",\"P\\u00e1ginas\":\"8\",\"Rompecabezas\":\"4 de 30 piezas\"}', NULL, NULL, '2026-07-13 01:16:52', '2026-07-13 01:16:52'),
(138, 'MI PRIMERA BIBLIOTECA DE TOY STORY', NULL, 'Una colección pensada para que los niños acompañen a Woody  y sus amigos a través de entretenidas aventuras. En sus páginas descubrirán que no hay nada que temer si tienes buenos amigos.\r\n\r\n \r\n\r\nTítulos:\r\n\r\nAventuras en el oeste, Dinosaurios en la selva, El guardín del espacio, Héroes y villanos, En la guardería, Lotso y su banda, Vacaciones en Hawai, Grandes momentos.', '{\"Tomos\":\"8\",\"Formato\":\"15 x 15 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra con marcador y juego\"}', NULL, NULL, '2026-07-13 01:18:29', '2026-07-13 01:18:29'),
(139, 'MI PRIMERA BIBLIOTECA DE HADAS (TINKERBELL)', NULL, 'Descubre el mágico mundo de las Hadas y acompaña a Tinker Bell en sus fascinantes aventuras. Con imágenes originales de la película, en excelente calidad.\r\n\r\n \r\n\r\nTítulos:\r\n\r\nEl nacimiento de Tinker Bell, El talento de Tinker Bell, La caja de música de Wendy, Tinker Bell en problemas, Tinker Bell y la piedra encantada, La nueva amiga de Tinker Bell, Hadas al rescate, Solo hay que crecer.', '{\"Tomos\":\"8\",\"Formato\":\"15 x 15 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra y marcador\"}', NULL, NULL, '2026-07-13 01:20:46', '2026-07-13 01:20:46'),
(140, 'MI PRIMERA BIBLIOTECA DE HELLO KITTY', NULL, 'Hello Kitty y sus amigos te esperan para descubrir juntos el mundo que nos rodea. ¡Acompáñalos y aprende los colores, los animales, las letras y mucho más!\r\n\r\n \r\n\r\nTítulos:\r\n\r\nEl clima, Los animales, Los colores, Las frutas, Los juguetes, Las letras, Los objetos, Los transportes.', '{\"Tomos\":\"8\",\"Formato\":\"15 x 21 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra y marcador\"}', NULL, NULL, '2026-07-13 01:23:17', '2026-07-13 01:23:17'),
(141, 'MI PRIMERA BIBLIOTECA DE APRENDO CON BARBIE', NULL, 'Barbie es una chica con una gran energía y con ganas de hacer siempre cosas nuevas y divertidas. Le encanta practicar deportes, cocinar y viajar y, sobre todo, adora pasar tiempo y compartir actividades con sus mejores amigos. Barbie es muy coqueta y le da mucha importancia a su cuidado personal, y también al de sus mascotas. ¡Ella ama y cuida a sus adoradas Lacy, Sequin y la gatita Blissa!\r\n\r\nTítulos:\r\n\r\nEl cuidado de la salud, El cuidado del cuerpo, El valor del esfuerzo, Alimentación  saludable, El valor de la alegría, A ser responsable, A compartir con amigos.', '{\"Tomos\":\"8\",\"Formato\":\"15 x 21 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra con marcador\"}', NULL, NULL, '2026-07-13 01:25:42', '2026-07-13 01:25:42'),
(142, 'MI PRIMERA BIBLIOTECA DE LA DOCTORA JUGUETES', NULL, 'Doc es una niña de seis años que puede hablar con sus animalitos de felpa y otros muñecos, a quienes cuida en su clínica para juguetes. A través de esta hermosa colección la podes acompañar en cada aventura.\r\n\r\n \r\n\r\nTítulos:\r\nRonda debe descansar, Mi amiga Kiko, Pasado por agua, Pisando fuerte, Abrazos de corazón, Tómalo con pinzas, Por culpa de la lluvia, Mensajes de radio.', '{\"Tomos\":\"8\",\"Formato\":\"15 x 21 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra con marcador\"}', NULL, NULL, '2026-07-13 01:26:56', '2026-07-13 01:26:56'),
(143, 'MI PRIMERA BIBLIOTECA PJ MASK', NULL, 'Una obra para que los más pequeños se entretengas con las increíbles aventuras de Catboy, Ululette y Gecko. Acompaña a estos pequeños superhéroes a derrotar villanos, a resolver misterios y aprender valiosas lecciones.\r\n\r\n \r\n\r\nTítulos:\r\n\r\n¿Qué pasó con Catboy?; Gecko resfriado; ¡Sé generosa, Ululette!; La coz de Gecko; ¿A dónde se fue el tren?; Héroes vs. Robots; Gecko y la piedra del poder; Carboy en dos ruedas.', '{\"Tomos\":\"8\",\"Formato\":\"15 x 211 cm\",\"P\\u00e1ginas\":\"10 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Medidor, m\\u00e1scaras y pizarra con marcador\"}', NULL, NULL, '2026-07-13 01:28:55', '2026-07-13 01:28:55'),
(144, 'MI PRIMERA BIBLIOTECA DE LA CASA DE MICKEY', NULL, 'Mickey y sus amigos te esperan para pasar junto a ellos divertidas aventuras mientras aprendemos jugando. ¡Acompáñalos y pasarás momentos muy divertidos en la casa de Mickey Mouse!\r\n\r\n \r\n\r\nTítulos:\r\n\r\n¡Vamos a volar!, Un rally entre amigos, Skates a toda velocidad, La naturaleza nos rodea, Diversión al aire libre, Día de pesca, Competencia de Barriletes, Banda de rock.', '{\"Tomos\":\"8\",\"Formato\":\"15 x 21 cm\",\"P\\u00e1ginas\":\"12 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra con marcador, l\\u00e1minas para recortar\"}', NULL, NULL, '2026-07-13 01:31:27', '2026-07-13 01:31:27'),
(145, 'LEE Y APRENDE LA HORA CON DISNEY JUNIOR', NULL, 'Comparte un día con tus personajes favoritos de Disney junior y aprende a leer la hora con el reloj de agujas móviles. Disfruta de 4 mini cuentos con Mickey, Doctora Juguetes, Princesita Sofía, Minnie. Juega para reconocer las horas, arma y pinta el rompecabezas y usa tus crayones favoritos para colorearlo del otro lado.\r\n\r\n \r\n\r\nTítulos:\r\n\r\nAprendo la hora con Disney Junior, Pequeños problemas, Vacaciones en el mar, Cena con amigos, Un corazón para San Valentín.', '{\"Tomos\":\"5\",\"Formato\":\"24 x 24 cm y 10 x 10 cm\",\"P\\u00e1ginas\":\"10\\/14 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Marcador y rompecabezas\"}', NULL, NULL, '2026-07-13 01:33:13', '2026-07-13 01:33:13'),
(146, 'MEGA ROMPECABEZAS – CARS  CUENTOS CON ROMPECABEZAS', NULL, 'Lee las fantásticas historias de CARS y diviértete armando apasionantes rompecabezas. Al final del libro encontrarás una lámina con todo lo necesario para jugar a ¡Motores en marcha!, un divertido juego de mesa para compartir y disfrutar junto a tus amigos. No esperes más, abre el libro y entra al mundo de Cars.', '{\"Tomos\":\"1\",\"Formato\":\"29 x 39 cm\",\"P\\u00e1ginas\":\"10\",\"Rompecabezas\":\"3 de 25 piezas\",\"Incluye\":\"L\\u00e1mina para recortar\"}', NULL, NULL, '2026-07-13 01:34:48', '2026-07-13 01:34:48'),
(147, 'APRENDER LOS NÚMEROS Y LAS FORMAS – MI LIBRO PIZARRA', NULL, 'Aprende junto a Lila y Tomy los números y las formas; y ayuda a desarrollar la motricidad fina de los más pequeños. Contiene imágenes que ilustran cada cifra. Incluye una aplicación para Tablet y Smartphone.\r\n\r\nTODAS LAS HOJAS PIZARRAS MÁGICAS\r\n\r\n- Dibujos para relacionar los números y las formas.\r\n\r\n- Letra punteada para practicar.\r\n\r\n- Líneas punteadas para orientar en el trazado.\r\n\r\n- Cuento breve con propuestas para jugar.', '{\"Tomos\":\"1\",\"Formato\":\"22 x 30 cm\",\"P\\u00e1ginas\":\"24\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Marcador con borrador\"}', NULL, NULL, '2026-07-13 01:37:03', '2026-07-13 01:37:03'),
(148, 'APRENDER LAS LETRAS – MI LIBRO PIZARRA', NULL, 'Aprende junto a Leo y Bianca las letras del alfabeto y ayuda a desarrollar la motricidad fina de los más pequeños. Indicación alfabética de mayúsculas y minúsculas. Incluye una aplicación para Tablet y Smartphone.\r\n\r\nTODAS LAS HOJAS PIZARRAS MÁGICAS\r\n\r\n- Dibujos para relacionar las letras.\r\n\r\n- Letra punteada para practicar.\r\n\r\n- Líneas punteadas para orientar en el trazado.\r\n\r\n- Cuento breve con propuestas para jugar.', '{\"Tomos\":\"1\",\"Formato\":\"22 x 30 cm\",\"P\\u00e1ginas\":\"24\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Marcador con borrador\"}', NULL, NULL, '2026-07-13 01:38:52', '2026-07-13 01:38:52'),
(149, 'EL PRINCIPITO EDICIÓN DE LUJO', NULL, 'La famosa novela escrita por el aviador y escritor Antoine de Saint-Exupéry, con las ilustraciones originales del autor. Se trata de un relato poético que atrapa a grandes y chicos, dejando en cada capítulo una enseñanza. Trata temas universales como el amor, la amistad, el sentido de la vida y la naturaleza humana. En versión maxi formato para disfrutar con la familia.', '{\"Tomos\":\"1\",\"Formato\":\"28 x 38 cm\",\"P\\u00e1ginas\":\"96\",\"Tapa\":\"Acolchada\"}', NULL, NULL, '2026-07-13 01:43:32', '2026-07-13 01:43:32'),
(150, 'COFRE MÁGICO CUENTOS CLÁSICOS', NULL, 'Los mejores cuentos clásicos en una sola colección. Los chicos podrán practicar su lectura, además de aprender valores y moralejas.\r\n\r\n \r\n\r\nTítulos:\r\nAladino y su lampara mágica, El Flautista de Hamelin, Pulgarcita, El agua de la vida, El sastrecillo valiente y El príncipe y el mendigo.', '{\"Tomos\":\"6\",\"Formato\":\"12 x 12 cm\",\"P\\u00e1ginas\":\"10 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n con manija\"}', NULL, NULL, '2026-07-13 01:44:51', '2026-07-13 01:44:51'),
(151, 'AVENTURAS CON AMIGOS MASHA Y EL OSO', NULL, 'Te damos la bienvenida al fascinante mundo de Masha y el Oso. Una obra increíble llena de historias, juegos y diversión. Los libros tratan las nociones básicas para los más pequeños. 4 Tomos con forma para armar un rompecabezas. 2 Tomos con pop up. 1 tomo para recortar y armar tus personajes. 1 Tomo para colorear. Incluye pizarra, marcador, actividades y juegos.', '{\"Etiqueta\":\"Agotado\",\"Tomos\":\"8\",\"Formato\":\"20 x 30 cm, 15 x 21 cm y 33 x 43 cm\",\"P\\u00e1ginas\":\"10 cada tomo\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra con marcador\"}', NULL, NULL, '2026-07-13 01:48:24', '2026-07-13 01:48:24'),
(152, 'CUENTOS QUE ILUMINAN  PEPPA PIG', NULL, 'Las mejores historias de Peppa Pig y sus amigos donde los chicos podrán trabajar los colores, los números, la motricidad fina, la memoria y lo más importante, que es divertirse junto a su personaje favorito.\r\n\r\nINCREIBLE JUEGO DE LUCES DE COLORES LED EN LA TAPA', '{\"Etiqueta\":\"Agotado\",\"Tomos\":\"1\",\"Formato\":\"34 x 46 cm\",\"P\\u00e1ginas\":\"12\",\"Tapa\":\"Con 25 luces led\",\"Incluye\":\"Marcador\"}', NULL, NULL, '2026-07-13 01:50:34', '2026-07-13 01:50:45'),
(153, 'LIGA DE LA JUSTICIA – DEFENSORES DEL PLANETA   LIBRO DE GOMA EVA', NULL, 'Basado en las historias de La Liga de la Justicia, este cuento ayuda a ejercitar la lectura y enseña sobre el trabajo en equipo. Fabuloso material de goma eva que lo resulta liviano para leer y trasladar. Incluye piezas extraíbles para armar y jugar. Con actividades y juegos con marcador.', '{\"Tomos\":\"1\",\"Formato\":\"38 x 48 cm\",\"P\\u00e1ginas\":\"10\",\"Incluye\":\"Marcador y piezas extra\\u00edbles\"}', NULL, NULL, '2026-07-13 01:55:54', '2026-07-13 01:55:54'),
(154, 'MASHA Y EL OSO – UN DÍA DE MERMELADAS LIBRO DE GOMA EVA', NULL, 'Acompaña a esta traviesa niña y a sus amigos en las aventuras por el bosque. Fabuloso material de goma eva que lo resulta liviano para leer y trasladar. Incluye piezas extraíbles para armar y jugar. Con actividades y juegos con marcador.', '{\"Etiqueta\":\"Agotado\",\"Tomos\":\"1\",\"Formato\":\"38 x 48 cm\",\"P\\u00e1ginas\":\"10\",\"Incluye\":\"Marcador y piezas extra\\u00edbles\"}', NULL, NULL, '2026-07-13 01:58:12', '2026-07-13 01:58:23'),
(155, 'CUENTOS CLÁSICOS PARA PRINCESAS ROMPECABEZAS GIGANTES', NULL, 'Las mejores historias de Princesas en una sola colección. Luego arma y juega con los rompecabezas gigantes. La bella durmiente, Cenicienta, La sirenita y La bella y la bestia.', '{\"Tomos\":\"1\",\"Formato\":\"28 x 38 cm\",\"P\\u00e1ginas\":\"12\",\"Rompecabezas\":\"3\"}', NULL, NULL, '2026-07-13 02:02:13', '2026-07-13 02:02:13'),
(156, 'AVENTURAS EN EL REINO INFANTIL ROMPECABEZAS GIGANTES', NULL, 'Los personajes del reino infantil se unen para contar aventuras, acompaña a Zenón y disfruta con los animalitos del zoo. Luego arma y juega con los rompecabezas gigantes.', '{\"Etiqueta\":\"Agotado\",\"Tomos\":\"1\",\"Formato\":\"28 x 38 cm\",\"P\\u00e1ginas\":\"12\",\"Rompecabezas\":\"3\"}', NULL, NULL, '2026-07-13 02:10:05', '2026-07-13 02:10:15'),
(157, 'COLECCIÓN TROQUE TROQUE CUENTOS', NULL, 'LIBROS DE GOMA EVA\r\n\r\nFabulosa colección de cuatro tomos hechos en goma eva para que los más chiquitos lean y jueguen de manera fácil. Frases amenas y divertidas para aprender las vocales, animales, colores, formas, transportes y números.\r\n\r\n \r\n\r\nTítulos:\r\nNúmeros del 1 al 5, Colores y Formas, Vocales y Animales, Transportes.', '{\"Tomos\":\"4\",\"Formato\":\"20 x 24 cm\",\"P\\u00e1ginas\":\"10 cada tomo\",\"Estuche\":\"Valija\",\"Incluye\":\"Piezas extra\\u00edbles para encastrar y jugar\"}', NULL, 'https://www.youtube.com/shorts/XlmAeNSjdGk?feature=share', '2026-07-13 02:12:38', '2026-07-13 02:13:11'),
(158, 'COLECCIÓN TROQUE CUENTOS BILINGÜES', NULL, 'LIBROS DE GOMA EVA\r\n\r\nFabulosa colección de cuatro tomos hechos en goma eva para que los pequeños aprendan sus primeras palabras en inglés. Frases bilingües y fáciles para aprender sobre frutas, mascotas, el hogar y el cuerpo humano.\r\n \r\nTítulos:\r\nMascotas, Mi hogar, Frutas y Mi cuerpo.', '{\"Tomos\":\"4\",\"Formato\":\"20 x 24 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\",\"Incluye\":\"Piezas extra\\u00edbles para encastrar y jugar\"}', NULL, NULL, '2026-07-13 02:16:09', '2026-07-13 02:16:09'),
(159, 'LOS TRES DESEOS LIBRO MÁGICO DE AGUA', NULL, 'Un cuento para disfrutar en familia que deja una hermosa enseñanza. A la ves te podes divertir pintando con la esponjita las páginas blancas. Descubrirás cómo aparece el color ¡MÁGICAMENTE!', '{\"Tomos\":\"1\",\"Formato\":\"33 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Rompecabezas\":\"2\",\"P\\u00e1ginas m\\u00e1gicas\":\"2\",\"Incluye\":\"Esponjita\"}', NULL, NULL, '2026-07-13 02:19:29', '2026-07-13 02:19:29'),
(160, 'LA GRANJA DE ZENÓN UNA MAÑANA MUY PARTICULAR', NULL, 'Ayuda a Zenón a entender que ha pasado en la granja con todos sus amigos. Descubrí sus cantos, mugidos, relinchos y parloteos a través de una increíble botonera.\r\n\r\n¡APRETA SOBRE LA IMÁGEN Y ESCUCHA LOS SONIDOS DE LA GRANJA!', '{\"Tomos\":\"1\",\"Formato\":\"28 x 38 cm\",\"P\\u00e1ginas\":\"20\",\"Incluye\":\"M\\u00f3dulo de sonido con 5 botones\"}', '1783898702_6a54224eba17c.mp4', NULL, '2026-07-13 02:25:02', '2026-07-13 02:25:02'),
(161, 'COLECCIÓN LENTICULAR NOCHE DE BRUJAS', NULL, 'Un original cuento con rima, donde los niños descubren que la vida de brujas es muy divertida. Incluye actividades y entretenidos juegos.\r\n\r\nINCREIBLE IMAGÉN LENTICULAR EN LA TAPA', '{\"Tomos\":\"1\",\"Formato\":\"38 x 48 cm\",\"P\\u00e1ginas\":\"20\",\"Incluye\":\"Marcador con borrador\"}', NULL, 'https://youtu.be/yfcX9647B8g', '2026-07-13 02:28:39', '2026-07-13 02:28:39'),
(162, 'COLECCIÓN LENTICULAR DINOSAURIOS - EL NIDO MISTERIOSO', NULL, 'Una apasionante historia ocurrida en el Museo de Ciencias Naturales. Además, datos curiosos acerca de los dinosaurios más conocidos. Incluye actividades y divertidos juegos.\r\n\r\nINCREIBLE IMAGÉN LENTICULAR EN LA TAPA', '{\"Tomos\":\"1\",\"Formato\":\"38 x 48 cm\",\"P\\u00e1ginas\":\"20\",\"Incluye\":\"Marcador con borrador\"}', NULL, 'https://youtu.be/UxKllg1r22o', '2026-07-13 02:35:13', '2026-07-13 02:35:13'),
(163, 'DINOSAURIOS TEXTURAS PARA LEER, SENTIR Y TOCAR', NULL, 'Acompaña a los dinosaurios en sus aventuras en distintos lugares. En la cual te harán sentir y tocar las diferentes texturas que te introducirán en su historia. Grandes y chicos se divertirán con los juegos y las actividades.', '{\"Tomos\":\"6\",\"Formato\":\"15 x 14 cm\",\"P\\u00e1ginas\":\"10 con diferentes texturas\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra con marcador, Juegos online y l\\u00e1minas para troquelar\"}', NULL, 'https://youtu.be/yxCfbyzvIho', '2026-07-13 02:48:19', '2026-07-13 02:48:19'),
(164, 'ANIMALES DE LA GRANJA PARA LEER, SENTIR Y TOCAR', NULL, 'Acompaña a los animales en sus aventuras en un día dentro de la granja. En la cual te harán sentir y tocar las diferentes texturas que te introducirán en su historia. Padres y chicos se divertirán con los juegos y las actividades que posee esta colección, memo test, laberinto, juego de mesa, escena para pintar, juego del sapito para embocar, pizarra mágica con marcador y mucho más.', '{\"Tomos\":\"6\",\"Formato\":\"15 x 14 cm\",\"P\\u00e1ginas\":\"10 con diferentes texturas\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Juegos online, pizarra con marcador y l\\u00e1minas para troquelar\"}', NULL, 'https://youtu.be/Pwn6pErGLXw', '2026-07-13 02:55:47', '2026-07-13 02:55:47'),
(165, 'ANIMALES DE LA SELVA PARA LEER, SENTIR Y TOCAR', NULL, 'Acompaña a los animales en sus aventuras en un día dentro de la selva. En la cual te harán sentir y tocar las diferentes texturas que te introducirán en su historia. Grandes y chicos se divertirán con los juegos y las actividades.', '{\"Etiqueta\":\"Agotado\",\"Tomos\":\"6\",\"Formato\":\"15 x 14 cm\",\"P\\u00e1ginas\":\"10 con diferentes texturas\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Pizarra con marcador y l\\u00e1minas para troquelar\"}', NULL, 'https://www.youtube.com/shorts/bhdBEvLGp74?feature=share', '2026-07-13 02:58:06', '2026-07-13 03:08:50'),
(166, 'LA GRANJA DE ZENON - PARA LEER, SENTIR Y TOCAR', NULL, 'Zenón junto a Bartolito, Lola, Percherón, Pepe, Doña Pancha y Lito juegan y se divierten dentro de la granja. En la cual podrás descubrir diferentes texturas para sentir y tocar. Grandes y chicos se divertirán con los juegos y las actividades.', '{\"Etiqueta\":\"Agotado\",\"Tomos\":\"6\",\"Formato\":\"15 x 14 cm\",\"P\\u00e1ginas\":\"10 con diferentes texturas\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"L\\u00e1minas para troquelar y pizarra con marcador\"}', NULL, NULL, '2026-07-13 03:08:04', '2026-07-13 03:08:04'),
(167, 'PRIMERA INFANCIA NOCIONES BÁSICAS', NULL, 'Fabulosa colección con colores y dibujos atractivos para que los más pequeños puedan reconocer fácilmente las nociones básicas y cotidianas.\r\n\r\nTítulos:\r\n\r\nColores; Juguetes; Números; Animales; Vocales y Frutas.', '{\"Etiqueta\":\"Pr\\u00f3ximamente\",\"Tomos\":\"6\",\"Formato\":\"15 x 14 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Caja de cart\\u00f3n con pizarra imantada\",\"Incluye\":\"50 fichas con imanes\"}', NULL, NULL, '2026-07-13 03:19:51', '2026-07-13 03:19:51'),
(168, 'JUGAR, ENSEÑAR Y APRENDER CON MANUALIDADES', NULL, 'Este libro de manualidades te propone originales proyectos para que llenes el aula de color y ternura. Hoy sabemos que los niños y niñas aprenden más a partir del juego y de las actividades compartidas. Por eso, te invitamos a trabajar con goma EVA, porcelana fría, papel, pañolenci y medias tejidas para crear objetos cálidos y amigables que tus estudiantes puedan disfrutar. También, a descubrir la potencialidad educativa de la cocina y del maquillaje artístico. Con todos los proyectos explicados paso a paso y veinte láminas de moldes. Para docentes de nivel inicial y primaria.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"160\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Incluye\":\"Moldes\"}', NULL, 'https://www.youtube.com/shorts/qsRjyLwbXRM?feature=share', '2026-07-13 03:23:33', '2026-07-13 03:23:33'),
(169, 'TRAYECTOS INCLUSIVOS EN EL ENTORNO EDUCATIVO', NULL, 'Este libro tiene la misión de ser una fuente de inspiración para que padres, docentes, profesionales y quienes integran equipos escolares generen nuevas ideas y desplieguen otras acciones en las prácticas pedagógicas. Está basado en el nuevo modelo social de la discapacidad y bajo esta perspectiva, invita al lector a ingresar al desafiante mundo de la educación inclusiva. Materiales de apoyo y recursos didácticos, ideas y conceptos, experiencias y respuestas a múltiples cuestionamientos se entrecruzan a lo largo de los diferentes capítulos.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"224\",\"Estuche\":\"Caja de cart\\u00f3n\",\"L\\u00e1minas\":\"22 de 48 x 68 cm\",\"Tapa\":\"Acolchada\"}', NULL, 'https://youtu.be/FyaHaFgSXKg', '2026-07-13 03:26:14', '2026-07-13 03:26:14'),
(170, 'CALENDARIO ESCOLAR PARA DOCENTES', NULL, 'DÍA X DÍA - EFEMÉRIDES - DISCURSOS - ACTOS\r\n \r\n\r\nEn este Calendario escolar, la idea es acompañar día a día el que hacer del docente en el aula, proponiendo una reflexión sobre lo que se celebra en esa fecha a nivel nacional, latinoamericano y mundial. Aunque generalmente se asocian las efemérides con las fiestas patrias, estas abarcan una gama de materiales que podrían, por sí solos, proporcionar contenido para todo el ciclo lectivo. En efecto, tenemos conmemoraciones históricas, científicas, vinculadas con la formación ciudadana y en valores, culturales, religiosas… Hemos incorporado, además, una fiesta regional por mes, de impacto en la cultura nacional.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"320\",\"Estuche\":\"Caja de cart\\u00f3n\",\"L\\u00e1minas\":\"8 de 48 x 68 cm\",\"Tapa\":\"Acolchada\"}', NULL, 'https://youtu.be/s9Rp1XizGc0', '2026-07-13 03:28:39', '2026-07-13 03:28:39'),
(171, 'FOLKLORE ARGENTINO LAS VOCES DEL PUEBLO', NULL, 'Una obra en la cual se propone una mirada profunda y abarcativa a todas las manifestaciones del folklore (la literatura, la música, las danzas, la gastronomía, la religiosidad, el lenguaje, los hábitos sociales, el transporte, la vivienda, las vestimentas, etc) a lo largo de los distintos ámbitos geográficos de nuestro país. Zulema Alcoyaga , su autora, es una conocidísima figura del folklore nacional, creadora del famoso personaje Margarito Tereré y de Canciones para argentinitos, entre muchas otras obras que manifiestan su interés en difundir nuestro patrimonio cultural, especialmente entre niños y los jóvenes. Cada capítulo termina con una propuesta para trabajar folklore según lo aprendido, mediante cuestionarios, juegos y actividades grupales, así como una síntesis de los principales conceptos aprendidos.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"224\",\"Estuche\":\"Caja de cart\\u00f3n\",\"Tapa\":\"Acolchada\"}', NULL, 'https://www.youtube.com/shorts/1aict2bBppI?feature=share', '2026-07-13 03:31:29', '2026-07-13 03:31:29'),
(172, 'EDUCACIÓN SEXUAL INTEGRAL ESI PRIMARIA', NULL, 'Poder enseñar ESI en la escuela es hoy, para nuestro educadores, una gran responsabilidad, pero al mismo tiempo una oportunidad única para tratar de contribuir y garantizar el bienestar de niños y niñas; y que se satisfaga su derecho a una educación de calidad.', '{\"Tomos\":\"1\",\"Formato\":\"24 x 34 cm\",\"P\\u00e1ginas\":\"320\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, 'https://www.youtube.com/shorts/v5rspuOx1KU?feature=share', '2026-07-13 03:36:24', '2026-07-13 03:36:24'),
(173, 'INTELIGENCIA LINGÜÍSTICA en el nivel inicial', NULL, 'Recursos para docentes y profesionales de la educación.\r\n\r\nEste libro propone un enfoque teórico y una implementación fundamentada para que el maestro de Nivel Inicial pueda analizar su propia práctica y construir estrategias didácticas acordes con las investigaciones más relevantes en la temática, intervenciones pedagógicas probadas y efectivas, y con el diseño curricular vigente.\r\nAdemás de conocer una variedad de actividades para enseñar Prácticas del Lenguaje, los lectores de este libro podrán aprender modos de tener en cuenta la diversidad y las diferentes habilidades de los alumnos. Analizarán cómo los conceptos de “individualización” y de “pluralización” pueden hacerse más presentes en las planificaciones y las propuestas didácticas “lingüísticas” de la sala.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"320\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 03:41:47', '2026-07-13 03:41:47'),
(174, 'DOCENTES EN EL AULA - NIVEL INICIAL Incluye sala de 2', NULL, 'Este libro está pensado para acompañar y nutrir la práctica docente de las salas de jardín, desde los dos años hasta sala de 5. Incluye unidades didácticas desarrolladas para cada edad, con contenidos curriculares según las distintas áreas de enseñanza y materiales propuestos, pensados a partir de las inteligencias múltiples.\r\n\r\nActividades, proyectos y ejercicios prácticos.', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"410\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 03:43:59', '2026-07-13 03:43:59'),
(175, 'DOCENTES EN EL AULA - PRIMER CICLO CIENCIAS SOCIALES', NULL, 'Ideas previas sobre los saberes que se van adquiriendo a lo largo del año, originales proyectos de investigación y conceptos para trabajar desde Conocimiento del Mundo.\r\n\r\n\r\n・PLANIFICACIONES\r\n\r\n・PROYECTOS\r\n\r\n・CONTENIDOS CURRICULARES\r\n\r\n・EJERCICIOS PRÁCTICOS\r\n\r\n・EVALUACIONES', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"320\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 03:46:33', '2026-07-13 03:46:33'),
(176, 'DOCENTES EN EL AULA - PRIMER CICLO CIENCIAS NATURALES', NULL, 'Incluye planificación según las competencias del siglo XXI, ideas previas sobre los saberes que se van adquiriendo a lo largo del año, originales proyectos de investigación y experimentos de habilidades de pensamiento.\r\n\r\n\r\n\r\n・PLANIFICACIONES\r\n\r\n・PROYECTOS\r\n\r\n・CONTENIDOS CURRICULARES\r\n\r\n・EJERCICIOS PRÁCTICOS\r\n\r\n・EVALUACIONES', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"320\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 03:48:00', '2026-07-13 03:48:00'),
(177, 'DOCENTES EN EL AULA - PRIMER CICLO LENGUA', NULL, 'El área de Lengua incluye ideas disparadoras, proyectos originales vinculados a cada unidad y recursos en red. También, fichas para trabajar y recortar.\r\n\r\n・PLANIFICACIONES\r\n\r\n・PROYECTOS\r\n\r\n・CONTENIDOS CURRICULARES\r\n\r\n・EJERCICIOS PRÁCTICOS\r\n\r\n・EVALUACIONES', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"320\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 03:49:51', '2026-07-13 03:49:51'),
(178, 'DOCENTES EN EL AULA - PRIMER CICLO MATEMÁTICAS', NULL, 'Estamos acostumbrados a que Matemática en la escuela sea hacer cuentas y cálculos, pero enseñar esta materia consiste en generar en el aula una actividad de producción de conocimiento semejante al quehacer de los matemáticos.\r\n\r\n・PLANIFICACIONES\r\n\r\n・PROYECTOS\r\n\r\n・CONTENIDOS CURRICULARES\r\n\r\n・EJERCICIOS PRÁCTICOS\r\n\r\n・EVALUACIONES', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"450\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 03:51:11', '2026-07-13 03:51:11'),
(179, 'DOCENTES EN EL AULA – SEGUNDO CICLO CIENCIAS SOCIALES', NULL, 'Una propuesta didáctica participativa para enseñar Ciencias Sociales en el Segundo Ciclo de la Educación Primaria \"Docentes en el Aula – Ciencias Sociales Segundo Ciclo\" ofrece a las y los docentes una serie de proyectos diseñados a partir de los contenidos curriculares oficiales, con un enfoque que prioriza la participación, el pensamiento crítico y la contextualización histórica, social y territorial.\r\nLas propuestas se destacan por:\r\nLa diversidad y progresiva complejidad de los temas abordados\r\nLa simultaneidad en el tratamiento de distintas problemáticas del área\r\nEl enfoque didáctico participativo, que valora el trabajo colaborativo y reflexivo\r\nLa articulación de teoría y práctica, con herramientas concretas para la planificación y el trabajo cotidiano en el aula\r\nCada proyecto incluye su planificación, secuencia didáctica, fundamentación teórica y actividades, facilitando el diseño de experiencias significativas que enriquezcan la enseñanza de las Ciencias Sociales.\r\n\r\nLáminas didácticas incluidas (formato 55 x 84 cm):\r\nLa independencia\r\nActividad económica\r\nMapa Bicontinental de la República Argentina – Político\r\nMapa Bicontinental de la República Argentina – Físico\r\n\r\n・PLANIFICACIONES\r\n\r\n・PROYECTOS PEDAGÓGICOS\r\n\r\n・CONTENIDOS CURRICULARES ACTUALIZADOS\r\n\r\n・EJERCICIOS PRÁCTICOS PARA EL AULA\r\n\r\n・EVALUACIONES LISTOS PARA APLICAR', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"402\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 04:14:32', '2026-07-13 04:14:32'),
(180, 'DOCENTES EN EL AULA – SEGUNDO CICLO CIENCIAS NATURALES', NULL, 'Una propuesta integral para enseñar Ciencias Naturales en el Segundo Ciclo de la Educación Primaria \"Docentes en el Aula – Ciencias Naturales Segundo Ciclo\" es una herramienta didáctica pensada para acompañar a los y las docentes en la planificación, el desarrollo y la evaluación de la enseñanza en el aula. Organizado de acuerdo con los lineamientos de la propuesta curricular actual, este material ofrece fichas de trabajo por eje temático, con actividades diseñadas para fomentar:\r\nLa observación sistemática\r\nLa recolección e interpretación de datos\r\nLa formulación de hipótesis\r\nEl intercambio de resultados y conclusiones\r\nLa participación activa y la reflexión colectiva\r\nAdemás, incorpora proyectos integradores, que promueven el aprendizaje significativo, la apropiación de los modos de conocer en ciencias, y la construcción de una mirada crítica y ética en relación con el entorno natural y social.\r\nIncluye 5 láminas didácticas en gran formato (55 x 84 cm), ideales para el trabajo visual en el aula.\r\n\r\nCambio climático y actividad humana\r\nLos seres vivos\r\nEras y períodos geológicos\r\nCambios en la materia\r\nEl cuerpo humano\r\n・PLANIFICACIONES\r\n\r\n・PROYECTOS PEDAGÓGICOS\r\n\r\n・CONTENIDOS CURRICULARES ACTUALIZADOS\r\n\r\n・EJERCICIOS PRÁCTICOS PARA EL AULA\r\n\r\n・EVALUACIONES LISTOS PARA APLICAR', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"404\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 04:15:49', '2026-07-13 04:15:49'),
(181, 'DOCENTES EN EL AULA – SEGUNDO CICLO PRÁCTICAS DEL LENGUAJE', NULL, 'Una propuesta pedagógica integral para enseñar lengua en el segundo ciclo de la educación primaria. \"Docentes en el Aula – Prácticas del Lenguaje Segundo Ciclo\" ha sido concebido como una herramienta práctica y versátil que acompaña al docente en su labor diaria. Su enfoque promueve un trabajo sostenido sobre el lenguaje oral y escrito, con actividades que favorecen el desarrollo progresivo de las competencias lingüísticas de los alumnos. Se destaca por: La diversidad y progresiva complejidad de las propuestas. La simultaneidad en el abordaje de distintos problemas del lenguaje. El énfasis en la lectura, escritura y oralidad en situaciones significativas. La construcción colectiva del conocimiento, favoreciendo la apropiación de textos propios, de pares y de autores diversos (noveles y consagrados). Incluye 5 láminas didácticas en gran formato (55 x 84 cm), ideales para el trabajo visual en el aula. Reglas de convivencia Las sílabas y el acento Reglas de acentuación El verbo El sustantivo\r\n\r\n\r\n\r\n・PLANIFICACIONES\r\n\r\n・PROYECTOS PEDAGÓGICOS\r\n\r\n・CONTENIDOS CURRICULARES ACTUALIZADOS\r\n\r\n・EJERCICIOS PRÁCTICOS PARA EL AULA\r\n\r\n・EVALUACIONES LISTOS PARA APLICAR', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"360\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 04:17:32', '2026-07-13 04:17:32'),
(182, 'DOCENTES EN EL AULA – SEGUNDO CICLO MATEMÁTICA', NULL, 'Una herramienta integral para la planificación y enseñanza de la matemática en el segundo ciclo de la educación primaria. \"Docentes en el Aula – Matemática Segundo Ciclo\" ofrece un desarrollo anual completo del área, alineado con los enfoques teóricos y lineamientos curriculares actuales. Este recurso permite transitar por una variedad de actividades diseñadas para implementar un hacer matemático significativo en el aula, con ejemplos concretos que facilitan el trabajo cotidiano de las y los docentes.\r\nIncluye propuestas prácticas que abarcan desde la planificación hasta la evaluación, con materiales visuales y recursos didácticos de gran utilidad.\r\nIncluye 5 láminas didácticas en formato gigante (55 x 84 cm) que refuerzan los contenidos clave:\r\n\r\nLos triángulos\r\nLos cuadriláteros\r\nNúmeros decimales\r\nNúmeros hasta el 10.000\r\nDecimales y fracciones\r\n・PLANIFICACIONES\r\n\r\n・PROYECTOS PEDAGÓGICOS\r\n\r\n・CONTENIDOS CURRICULARES ACTUALIZADOS\r\n\r\n・EJERCICIOS PRÁCTICOS PARA EL AULA\r\n\r\n・EVALUACIONES LISTOS PARA APLICAR', '{\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"452\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 04:18:48', '2026-07-13 04:18:48'),
(183, 'PEPPA PIG - LIBRO ALMOHADA', NULL, 'UN CUENTO PARA IR A DORMIR\r\nGeorge disfruta de emocionantes aventuras cuando Peppa le cuenta una historia para que se duerma. Libro de tela acolchado que se convertirán en la mejor compañía para siestas y viajes.', '{\"Etiqueta\":\"Agotado\",\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:20:50', '2026-07-13 05:20:50'),
(184, 'DINOSAURIOS - LIBRO ALMOHADA', NULL, 'UN CUENTO DE DINOSAURIOS\r\nAcompaña tus sueños y aventuras con esta delicada colección. Libro de tela que se convertirán en la mejor compañía para siestas y viajes.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46  cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:22:15', '2026-07-13 05:22:15'),
(185, 'UNA ORQUESTA EN LA SELVA – LIBRO ALMOHADA', NULL, 'Acompaña tus sueños y aventuras con esta delicada colección donde los pequeños podrán disfrutar de un cuento  con simpaticos animales. Libro de tela acolchado que se convertirán en la mejor compañía para siestas y viajes.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:23:52', '2026-07-13 05:23:52'),
(186, 'PATITO FEO - LIBRO ALMOHADA', NULL, 'Los mejores cuentos clásicos ilustrados especialmente los cuales atrapan la atención de los chicos. Libro de tela acolchado que se convertirán en la mejor compañía para siestas y viajes.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:25:09', '2026-07-13 05:25:09'),
(187, 'LOS TRES CHANCHITOS - LIBRO ALMOHADA', NULL, 'Los mejores cuentos clásicos ilustrados especialmente los cuales atrapan la atención de los chicos. Libro de tela acolchado que se convertirán en la mejor compañía para siestas y viajes.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:26:16', '2026-07-13 05:26:16'),
(188, 'PINOCHO - LIBRO ALMOHADA', NULL, 'Los mejores cuentos clásicos ilustrados especialmente los cuales atrapan la atención de los chicos. Libro de tela acolchado que se convertirán en la mejor compañía para siestas y viajes.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:27:08', '2026-07-13 05:27:08'),
(189, 'CAPERUCITA ROJA - LIBRO ALMOHADA', NULL, 'Los mejores cuentos clásicos ilustrados especialmente los cuales atrapan la atención de los chicos. Libro de tela acolchado que se convertirán en la mejor compañía para siestas y viajes.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:28:09', '2026-07-13 05:28:09'),
(190, 'LA REINA DE LAS NIEVES - LIBRO ALMOHADA', NULL, 'Los mejores cuentos clásicos ilustrados especialmente los cuales atrapan la atención de los chicos. Libro de tela acolchado que se convertirán en la mejor compañía para siestas y viajes.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:28:57', '2026-07-13 05:28:57'),
(191, 'SAN LORENZO DE ALMAGRO - LIBRO ALMOHADA', NULL, 'PRODUCTO OFICIAL\r\n¡Acompaña a los cuervos a todos lados! Un verdadero libro almohada con la historia de tu club favorito.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:30:06', '2026-07-13 05:30:06'),
(192, 'RACING CLUB - LIBRO ALMOHADA', NULL, 'PRODUCTO OFICIAL\r\n¡Acompaña a la Acade\' a todos lados! Un verdadero libro almohada con la historia de tu club favorito.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:31:12', '2026-07-13 05:31:12'),
(193, 'INDEPENDIENTE - LIBRO ALMOHADA', NULL, 'PRODUCTO OFICIAL\r\n \r\n¡Acompaña a los diablos a todos lados! Un verdadero libro almohada con la historia de tu club favorito.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:32:08', '2026-07-13 05:32:08'),
(194, 'BOCA JUNIORS - LIBRO ALMOHADA', NULL, 'PRODUCTO OFICIAL\r\n¡Lleva el azul y amarillo a todo lados! Un verdadero libro almohada con la historia de tu club favorito.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:33:06', '2026-07-13 05:33:06');
INSERT INTO `libros` (`id`, `titulo`, `subtitulo`, `descripcion`, `caracteristicas`, `video_archivo`, `video_url`, `created_at`, `updated_at`) VALUES
(195, 'RIVER PLATE - LIBRO ALMOHADA', NULL, 'PRODUCTO OFICIAL\r\n¡Acompaña al millo a todos lados! Un verdadero libro almohada con la historia de tu club favorito.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Vallija\"}', NULL, NULL, '2026-07-13 05:34:16', '2026-07-13 05:34:16'),
(196, 'LA GRANJA DE ZENON - LIBRO ALMOHADA', NULL, 'JUGANDO A LAS ESCONDIDAS\r\nAcompaña a Zenón a hacer sus compras, mientras que sus amigos aprovecharon para jugar en la granja. Libro de tela acolchado que se convertirán en la mejor compañía para siestas y viajes.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:35:24', '2026-07-13 05:35:24'),
(197, '¡SOMOS CAMPEONES! SELECCIÓN ARGENTINA - LIBRO ALMOHADA', NULL, 'PRODUCTO OFICIAL\r\nReviví el paso a paso de la selección Argentina en el mundial de Qatar 2022.', '{\"Tomos\":\"1\",\"Formato\":\"31 x 46 cm\",\"P\\u00e1ginas\":\"10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:36:40', '2026-07-13 05:36:40'),
(198, 'DULCES SUEÑOS - BOCA JUNIORS:', NULL, 'Bolsa de dormir. Desde 1905 nace la verdadera pasión.\r\nConoce la cronología de tu club favorito.\r\nIncluye estuche con forma de mochila.', '{\"Tomos\":\"1\",\"Formato\":\"1,20 x 0,85\",\"Estuche\":\"Mochila\"}', NULL, NULL, '2026-07-13 05:38:43', '2026-07-13 05:38:43'),
(199, 'DULCES SUEÑOS - TORTUGA', NULL, 'Bolsa de dormir. Hermosa fábula sobre la Liebre y la Tortuga que se convierte en una bolsa de dormir. Incluye estuche con forma de mochila.', '{\"Tomos\":\"1\",\"Formato\":\"1.20 x 0.85\",\"Estuche\":\"Mochila\"}', NULL, NULL, '2026-07-13 05:40:18', '2026-07-13 05:40:18'),
(200, 'DULCES SUEÑOS - LA GRANJA DE ZENON', NULL, 'HAPPY CAMPERS (Bolsa de dormir)\r\nAcompaña a Zenón en esta nueva aventura bajo las estrellas. La colección se convierte en una bolsa de dormir. ¡Incluye estuche en forma de mochila!', '{\"Tomos\":\"1\",\"Formato\":\"1.20 x 0.85\",\"Estuche\":\"Mochila\"}', NULL, 'https://youtu.be/OJi5AE78Yg8', '2026-07-13 05:42:25', '2026-07-13 05:42:54'),
(201, 'MI PRIMER ABECEDARIO', NULL, 'Hermosa colección para que los más pequeños aprendan a reconocer las letras relacionándolas con dibujos y palabras.', '{\"Tomos\":\"1 para colorear\",\"Tapa\":\"R\\u00fastica\",\"Fichas\":\"27\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:45:17', '2026-07-13 05:45:17'),
(202, 'CUBOLANDIA - CUERPO HUMANO', 'SET DE 8 CUBOS', 'Hermosa colección de cubos de goma espuma en los cuales podrás armar y aprender sobre los diferentes sistemas. Sistema Circulatorio, Sistema Respiratorio, Sistema Digestivo, Sistema Muscular, Sistema Oseo, Sistema Nervioso.', '{\"Tomos\":\"8 cubos de goma espuma\",\"Formato\":\"10 x 10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:50:21', '2026-07-13 21:11:35'),
(203, 'CUBOLANDIA', 'SET DE 8 CUBOS', 'Hermosa colección de cubos de goma espuma con los cuales podrás armar, jugar y aprender con distintas actividades. Cuento \"Misterio en el océano\", cuento \"Cumpleaños en la granja\", Aprendo las frutas (inglés/español), Aprendo de menor a mayor, Puzzle \"La granja\", Aprendo los colores (inglés/español).', '{\"Tomos\":\"8 cubos de goma espuma\",\"Formato\":\"10 x 10\",\"Estuche\":\"Valija\"}', NULL, NULL, '2026-07-13 05:53:17', '2026-07-13 21:11:23'),
(204, 'EDUCACIÓN SEXUAL', 'Crecer, conocernos y cuidarnos', 'En este libro ofrecemos reflexiones y propuestas prácticas para colaborar con el docente en la creación de las condiciones y en la orientación e sus estudiantes para vivir la sexualidad de manera respetuosa, inclusiva y Consciente.\r\nIncluye fichas con actividades para imprimir para docentes y estudiantes (Primer ciclo y segundo ciclo).\r\n\r\nEl cuidado del cuerpo y la salud\r\nAfectividad y respeto\r\nLas emociones en el aula\r\nVínculos familiares y de amistad\r\nComunicación y resolución de conflictos\r\nDiversidad e inclusión\r\nDerechos de niñas, niños y adolescentes\r\nPrevención y autoprotección\r\n\r\nDocentes en el aula : Serie Temas Transversales', '{\"Etiqueta\":\"Novedad\",\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"208\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 05:55:08', '2026-07-13 21:05:45'),
(205, 'VIOLENCIA ESCOLAR', 'Estrategias para resolver conflictos en la escuela', 'Ofrecemos herramientas prácticas para gestionar situaciones conflictivas entre pares, y entre estudiantes y adultos de la comunidad escolar. Trabajamos sobre casos concretos, los analizamos y proponemos posibles abordajes.\r\nIncluye fichas con actividades para imprimir para docentes y estudiantes (Primer ciclo y segundo ciclo).\r\n\r\nEscenario de conflictos\r\nViolencia reales y virtuales\r\nLa violencia y la institución escolar\r\nHistorias de aula\r\nPerspectivas y desafíos a futuro\r\nViolencias y agresión\r\nEstrategias de resolución de conflictos\r\nActividades para el docente y para los estudiantes\r\n\r\nDocentes en el aula - Serie Temas Transversales', '{\"Etiqueta\":\"Novedad\",\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"208\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 05:55:59', '2026-07-13 21:05:34'),
(206, 'MOCHILA DE EMOCIONES', 'Propuestas para una educación emocional', 'A través de poemas y fichas de actividades, buscamos facilitar el diálogo, la exploración y la comprensión de las emociones que sentimos todas las personas.\r\nIncluye fichas con actividades para imprimir para docentes y estudiantes (Primer ciclo y segundo ciclo).\r\n\r\n·Alegría\r\n·Ansiedad\r\n·Asombro\r\n·Tristeza\r\n·Miedo\r\n·Orgullo\r\n·Tedio\r\n·Celos\r\n·Enojo\r\n·Confianza\r\n·Admiración\r\n·Gratitud\r\n\r\nDocentes en el aula - Serie Temas Transversales', '{\"Etiqueta\":\"Novedad\",\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"208\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 05:57:07', '2026-07-13 21:05:23'),
(207, 'INTELIGENCIA ARTIFICIAL EN LA ESCUELA', 'La IA como herramienta didáctica', 'Este libro acerca al información sobre qué es la IA, describe los avances en el tema, cómo interactuar con esta tecnología y cómo trabajarla con los estudiantes.\r\nIncluye fichas con actividades para imprimir para docentes y estudiantes (Primer ciclo y segundo ciclo).\r\n\r\n¿Qué es y cómo funciona?\r\nRedes generativas\r\nUso de IA en la educación\r\nHerramientas para la educación\r\nDiseño de prompts\r\nContenido transversal\r\nPropuestas para áreas curriculares\r\nActividades para el docente y para los estudiantes\r\n\r\nDocentes en el aula - Serie Temas Transversales', '{\"Etiqueta\":\"Novedad\",\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"208\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 05:58:22', '2026-07-13 21:05:09'),
(208, 'PENSAR LA NEURODIVERSIDAD', 'Neurodivergencias y neurodiversidad en el aula', 'Esta obra acerca al docente herramientas conceptuales y dinámicas que hagan posible el encuentro con ese estudiante más allá de rótulos, estereotipos y estigmatizaciones sociales.\r\nIncluye fichas con actividades para imprimir para docentes y estudiantes (Primer ciclo y segundo ciclo).\r\n\r\nTrastornos infantiles y su relación con la educación\r\nNormalidad\r\nEtiquetas e identidades\r\nMarcos teóricos\r\nAbordaje interdisciplinario\r\nLa inclusión del niño neurodivergente\r\nNeurodiversidad y estrategias pedagógicas\r\nLas habilidades sociales\r\nActividades para el docente y para los estudiantes\r\n\r\nDocentes en el aula - Serie Temas Transversales', '{\"Etiqueta\":\"Novedad\",\"Tomos\":\"1\",\"Formato\":\"20 x 28 cm\",\"P\\u00e1ginas\":\"208\",\"Estuche\":\"Caja de cart\\u00f3n\"}', NULL, NULL, '2026-07-13 05:59:22', '2026-07-13 20:44:02'),
(209, 'COLECCIÓN ROTA CLÁSICOS', NULL, 'Hermosa obra especialmente ilustrada para atraer a los más pequeños. Encuadernado con el sistema rotafolio, donde los chicos solo ven la imagen y el adulto la lectura. Incluye preguntas disparadoras.\r\n\r\nTítulos:\r\n\r\nCaperucita Roja, Patito feo, Pinocho y Los Tres Chanchitos.', '{\"Tomos\":\"1\",\"Formato\":\"29 x 41 cm\",\"P\\u00e1ginas\":\"64\"}', NULL, NULL, '2026-07-13 16:46:10', '2026-07-13 16:46:10');
